INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('dbe69719-7467-5553-b041-582274c30530', 'math-4eme', 'القسمة الإقليدية', 'معنى القسمة (التوزيع بالتساوي والتجميع) ومصطلحاتها (المقسوم والمقسوم عليه والخارج والباقي)، العلاقة الأساسية المقسوم = (المقسوم عليه × الخارج) + الباقي مع الباقي < المقسوم عليه، تقنية القسمة المنصوبة على عددٍ ذي رقمٍ واحد، القسمة التامّة والقسمة بباقٍ، وحلّ مسائل التوزيع والتجميع. المقسوم من رقمين إلى أربعة أرقام والمقسوم عليه عددٌ ذو رقمٍ واحد.', '# ⚔️ القسمة الإقليدية — فنّ التوزيع بالعدل

> 💡 «عندك كنزٌ وتريد قسمته على رفاقك بالتساوي؟ القسمة هي السلاح الذي يقول لك: كم لكلّ واحد؟ وكم يتبقّى؟»

أهلًا بك أيّها البطل! تعرف الآن **الضرب**، وهو جمعُ العدد نفسِه مرّاتٍ كثيرة. اليوم نتعلّم عمليّته العكسيّة: **القسمة**. بها نوزّع كميّةً على مجموعاتٍ متساوية، فنعرف نصيب كلّ مجموعة، وكم يتبقّى خارج التوزيع.

## 🏰 ما معنى القسمة؟

للقسمة معنيان، وكلاهما يقودنا إلى العمليّة نفسها:

- **التوزيع بالتساوي:** عندك 12 جوهرة توزّعها على 3 صناديق بالعدل. كم جوهرةً في كلّ صندوق؟ الجواب 4، لأنّ 3 × 4 = 12.
- **التجميع:** عندك 12 جوهرة وتضع في كلّ صندوقٍ 4 جواهر. كم صندوقًا تملأ؟ الجواب 3 صناديق.

في الحالتين نكتب العمليّة بعلامة القسمة ÷ هكذا:

$$12 ÷ 3 = 4$$

ونقرؤها «**12 مقسومًا على 3 يساوي 4**». القسمة إذن هي البحث عن العدد الذي إذا ضربناه في المقسوم عليه أعطانا المقسوم.

## 🧮 مصطلحات القسمة

لكلّ عددٍ في القسمة اسمٌ خاصّ. تأمّل المثال 13 ÷ 4:

| المصطلح          | المعنى                              | في 13 ÷ 4 |
| ---------------- | ----------------------------------- | --------- |
| **المقسوم**      | العدد الذي نوزّعه (الكميّة الأصليّة) | 13        |
| **المقسوم عليه** | عدد المجموعات (أو نصيب المجموعة)     | 4         |
| **الخارج**       | نصيب كلّ مجموعة (نتيجة القسمة)       | 3         |
| **الباقي**       | ما يتبقّى ولا يكفي لتوزيعٍ جديد      | 1         |

في 13 ÷ 4: نوزّع 13 على 4، فيأخذ كلٌّ منها 3 (هذا الخارج)، ويتبقّى 1 (هذا الباقي) لأنّ 4 × 3 = 12 و 13 − 12 = 1.

> 🗡️ لا تخلط بين **الخارج** و**الباقي**: الخارج هو النصيب (كم لكلّ مجموعة)، والباقي هو الفائض (ما لم يُوزَّع).

## 🔮 العلاقة الأساسيّة

كلّ قسمةٍ تخضع لقاعدةٍ ذهبيّة تربط أعدادها الأربعة:

$$المقسوم = (المقسوم عليه × الخارج) + الباقي$$

ومعها شرطٌ لا يُخالَف أبدًا: **الباقي < المقسوم عليه**. فلو كان الباقي يساوي المقسوم عليه أو أكبر منه، لَأمكن توزيعه مرّةً أخرى، فالخارج لم يكتمل بعدُ.

_مثال محسوب:_ في 13 ÷ 4 وجدنا الخارج 3 والباقي 1. نتحقّق: (4 × 3) + 1 = 12 + 1 = 13 ✓، والباقي 1 أصغر من المقسوم عليه 4 ✓. القسمة صحيحة.

> ⚠️ الفخّ الأشهر: ترك باقٍ ≥ المقسوم عليه. مثلًا في 13 ÷ 4 لا يصحّ أن نقول «الخارج 2 والباقي 5»، لأنّ 5 ليست أصغر من 4؛ يجب أن نأخذ 4 مرّةً أخرى فيصير الخارج 3 والباقي 1.

## 🛡️ القسمة المنصوبة على عددٍ ذي رقمٍ واحد

عندما يكبر المقسوم نستعمل **القسمة المنصوبة**: نقسم رقمًا رقمًا من اليسار إلى اليمين. لنقسم 75 ÷ 5:

- **رقم العشرات:** 7 ÷ 5 يعطي 1 (نكتب 1 في الخارج)، والباقي 7 − 5 = 2.
- **ننزّل رقم الآحاد** 5 بجانب الباقي 2 فنحصل على 25.
- **رقم الآحاد:** 25 ÷ 5 يعطي 5 (نكتب 5 في الخارج)، والباقي 25 − 25 = 0.

إذن 75 ÷ 5 = 15 والباقي 0. نتحقّق: (5 × 15) + 0 = 75 ✓.

جرّب مثالًا أكبر، 98 ÷ 4:

- **رقم العشرات:** 9 ÷ 4 يعطي 2، والباقي 9 − 8 = 1.
- **ننزّل** رقم الآحاد 8 بجانب 1 فنحصل على 18.
- **رقم الآحاد:** 18 ÷ 4 يعطي 4، والباقي 18 − 16 = 2.

إذن 98 ÷ 4 = 24 والباقي 2. نتحقّق: (4 × 24) + 2 = 96 + 2 = 98 ✓.

> 🗡️ في كلّ خطوةٍ يجب أن يكون الباقي الجزئيّ أصغر من المقسوم عليه قبل أن تنزّل الرقم الموالي. إن كان أكبر فقد اخترت رقمًا صغيرًا في الخارج.

## 🧪 القسمة التامّة والقسمة بباقٍ

نميّز بين حالتين حسب الباقي:

- **قسمة تامّة:** الباقي = 0، أي أنّ التوزيع تمّ بالكامل دون فائض. مثل 12 ÷ 3 = 4 (الباقي 0). نقول إنّ 12 **مضاعفٌ** للعدد 3.
- **قسمة بباقٍ:** الباقي ≠ 0، أي يتبقّى فائضٌ لا يكفي لتوزيعٍ جديد. مثل 13 ÷ 4 = 3 والباقي 1.

## 📐 حلّ المسائل: نصيب أم عدد مجموعات؟

في المسائل اقرأ السؤال جيّدًا لتعرف ما تبحث عنه:

- إن سُئلت عن **نصيب كلّ مجموعة** أو **عدد المجموعات**، فالجواب هو **الخارج**.
- إن سُئلت عمّا **يتبقّى** أو **يفيض**، فالجواب هو **الباقي**.

_مثال:_ عند توزيع 30 حلوى على 4 أطفال بالتساوي: 30 ÷ 4 = 7 والباقي 2. فيأخذ كلّ طفلٍ 7 حلوياتٍ (الخارج)، وتبقى 2 (الباقي). نتحقّق: (4 × 7) + 2 = 30 ✓.

> 🏆 رائع أيّها البطل! صرت تعرف معنى القسمة ومصطلحاتها، وتُتقن العلاقة الأساسيّة المقسوم = (المقسوم عليه × الخارج) + الباقي مع الباقي < المقسوم عليه، وتنصب القسمة على عددٍ ذي رقمٍ واحد. وحين لا تكون القسمة تامّة ويبقى فائض، يولد سلاحٌ جديد لتقسيم الوحدة نفسها: **الكسور البسيطة** في الفصل القادم. تقدّم بثقة!', '# 📜 ملخّص: القسمة الإقليدية

- **معنى القسمة:** توزيعٌ بالتساوي (نصيب كلّ مجموعة) أو تجميعٌ (عدد المجموعات)، ونكتبها بعلامة ÷، مثل 12 ÷ 3 = 4.
- **المصطلحات:** **المقسوم** هو الكميّة الموزّعة، و**المقسوم عليه** عدد المجموعات، و**الخارج** نتيجة القسمة، و**الباقي** الفائض غير الموزّع.
- **العلاقة الأساسيّة:** المقسوم = (المقسوم عليه × الخارج) + الباقي، مع **الباقي < المقسوم عليه** دائمًا. مثال: 13 ÷ 4 → (4 × 3) + 1 = 13.
- **القسمة المنصوبة:** نقسم من اليسار رقمًا رقمًا، ننزّل الرقم الموالي بجانب كلّ باقٍ جزئيّ، مثل 98 ÷ 4 = 24 والباقي 2.
- **قسمة تامّة وقسمة بباقٍ:** الباقي = 0 قسمةٌ تامّة (12 ÷ 3 = 4)، والباقي ≠ 0 قسمةٌ بباقٍ (13 ÷ 4 = 3 والباقي 1).
- **في المسائل:** الخارج يجيب عن «نصيب كلٍّ» أو «عدد المجموعات»، والباقي يجيب عمّا «يتبقّى أو يفيض».
- **التحقّق دائمًا:** أعد حساب (المقسوم عليه × الخارج) + الباقي، يجب أن يساوي المقسوم، والباقي أصغر من المقسوم عليه.', 6)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('dd3eb949-8866-5004-b71c-00fa07d2234d', 'math-4eme', 'الكسور البسيطة', 'معنى الكسر كجزء من وحدة مجزّأة إلى أجزاء متساوية، البسط والمقام ومعنى كلٍّ منهما، قراءة وكتابة الكسور بصيغة a/b، الكسور المرجعية (النصف 1/2 والثلث 1/3 والربع 1/4 والأعشار)، تمثيل الكسر بشكلٍ مجزّأ بعض أجزائه ملوّنة، حساب الكسر من كمية، ومقارنة كسرين لهما نفس المقام', '# ⚔️ الكسور البسيطة — كنزٌ مقسومٌ بالعدل

> 💡 «حين لا يكفي العدد الصحيح، يأتي الكسر ليقول: خذ جزءًا واحدًا من أجزاءٍ متساوية.»

أهلًا أيّها البطل! تعلّمت في الفصل السابق **القسمة الإقليدية**: كيف نوزّع كمّيةً على أجزاء. اليوم نخطو خطوةً أبعد. ماذا لو قسمنا **رغيفًا واحدًا** بين 4 أصدقاء بالعدل؟ لا يأخذ كلٌّ منهم رغيفًا كاملًا، بل **جزءًا** منه. هذا الجزء اسمه **الكسر**. في هذه المغامرة نتعلّم معنى الكسر، ونقرؤه ونكتبه، ونحسبه من كمية، ونقارن بين كسرين.

## 🍕 ما هو الكسر؟ تجزئة الوحدة

نأخذ **وحدةً** واحدة (قرصًا، شريطًا، رغيفًا) ونقسمها إلى **أجزاء متساوية تمامًا**. الكسر هو **عددٌ من هذه الأجزاء المتساوية**.

انظر إلى هذا القرص: قسمناه إلى 4 أجزاء متساوية، ولوّنّا **جزءًا واحدًا**:

<svg viewBox="0 0 100 100"><circle cx="50" cy="50" r="40" fill="none" stroke="currentColor" stroke-width="2.5"/><path d="M50 50 L90 50 A40 40 0 0 0 50 10 Z" fill="#d1d5db" stroke="currentColor" stroke-width="2"/><line x1="10" y1="50" x2="90" y2="50" stroke="currentColor" stroke-width="2"/><line x1="50" y1="10" x2="50" y2="90" stroke="currentColor" stroke-width="2"/></svg>

الجزء الملوّن هو **جزءٌ واحد من 4 أجزاء متساوية**، فنكتبه **1/4** (نقرؤه: «واحد على أربعة» أو «رُبع»). **الشرط الذهبيّ:** لا يكون الكسر صحيحًا إلّا إذا كانت الأجزاء **متساوية**.

> 🗡️ الأجزاء يجب أن تكون متساوية! إن قسمت الوحدة إلى قطعٍ مختلفة المساحة، فلا يصحّ أن تسمّي القطعة كسرًا.

## 🔢 البسط والمقام: عددان لكلٍّ معنى

نكتب الكسر بصيغة **a/b** (عددان يفصل بينهما خطّ). لكلّ عددٍ اسمٌ ومعنى:

- **المقام** (العدد تحت الخطّ، b): يقول **إلى كم جزءٍ متساوٍ قسمنا الوحدة كلّها**.
- **البسط** (العدد فوق الخطّ، a): يقول **كم جزءًا أخذنا (لوّنّا)**.

في الكسر **3/4**: المقام 4 (قسمنا إلى 4 أجزاء)، والبسط 3 (أخذنا منها 3). انظر:

<svg viewBox="0 0 100 100"><circle cx="50" cy="50" r="40" fill="none" stroke="currentColor" stroke-width="2.5"/><path d="M50 50 L50 10 A40 40 0 1 0 90 50 Z" fill="#d1d5db" stroke="currentColor" stroke-width="2"/><line x1="10" y1="50" x2="90" y2="50" stroke="currentColor" stroke-width="2"/><line x1="50" y1="10" x2="50" y2="90" stroke="currentColor" stroke-width="2"/></svg>

3 أجزاء ملوّنة من 4 ⟵ **3/4**.

> ⚠️ الفخّ الشائع: لا تقلب الكسر! **البسط فوق** (ما أخذنا) و**المقام تحت** (عدد الأجزاء كلّها). «جزءان من 5» تُكتب 2/5، لا 5/2.

## 📏 الكسور المرجعية: النصف والثلث والربع

ثلاثة كسورٍ نلتقي بها كثيرًا، احفظها جيّدًا:

| الكسر | القراءة | المعنى | الشكل المجزّأ |
| ----- | ------- | -------------------------------- | ----------------- |
| 1/2   | نِصف    | جزءٌ واحد من **جزأين** متساويين  | الوحدة نصفان       |
| 1/3   | ثُلث    | جزءٌ واحد من **3 أجزاء** متساوية | الوحدة 3 أثلاث      |
| 1/4   | رُبع    | جزءٌ واحد من **4 أجزاء** متساوية | الوحدة 4 أرباع     |

وهذا شريطٌ قُسم نصفين، لُوّن نصفه (1/2):

<svg viewBox="0 0 100 60"><rect x="10" y="15" width="80" height="30" fill="none" stroke="currentColor" stroke-width="2.5"/><rect x="10" y="15" width="40" height="30" fill="#d1d5db" stroke="currentColor" stroke-width="2"/><line x1="50" y1="15" x2="50" y2="45" stroke="currentColor" stroke-width="2"/></svg>

**الأعشار:** إذا قسمنا الوحدة إلى **10 أجزاء متساوية**، فكلّ جزءٍ هو **عُشر = 1/10**. وثلاثة أجزاء هي 3/10. الأعشار مهمّة جدًّا (المتر والدينار يُقسمان إلى أعشار).

## 🍎 الكسر من كمية

أحيانًا نريد **كسرًا من مجموعةٍ من الأشياء**، لا من قرصٍ واحد. القاعدة سهلة: **اقسم الكمّية على المقام، ثمّ اضرب في البسط.**

*مثال محسوب:* ما هو **1/4 من 12** تفّاحة؟ المقام 4، فنقسم: 12 ÷ 4 = 3. والبسط 1، فالجواب **3** تفّاحات. تحقّق: 4 مجموعاتٍ من 3 تساوي 12 ✓.

<svg viewBox="0 0 120 40"><circle cx="14" cy="20" r="7" fill="#d1d5db" stroke="currentColor" stroke-width="2"/><circle cx="32" cy="20" r="7" fill="#d1d5db" stroke="currentColor" stroke-width="2"/><circle cx="50" cy="20" r="7" fill="#d1d5db" stroke="currentColor" stroke-width="2"/><circle cx="68" cy="20" r="7" fill="none" stroke="currentColor" stroke-width="2"/><circle cx="86" cy="20" r="7" fill="none" stroke="currentColor" stroke-width="2"/><circle cx="104" cy="20" r="7" fill="none" stroke="currentColor" stroke-width="2"/></svg>

*مثال آخر:* ما هو **1/3 من 15**؟ نقسم 15 ÷ 3 = 5، فالجواب **5**.

> 🗡️ الترتيب: أوّلًا القسمة على **المقام** (عدد الأجزاء)، ثمّ الضرب في **البسط** (عدد الأجزاء المأخوذة).

## ⚖️ مقارنة كسرين لهما نفس المقام

إذا كان لكسرين **نفس المقام**، فالأجزاء من **نفس الحجم**، ويكفي أن ننظر إلى **البسط**: **الأكبر بسطًا هو الأكبر**.

مثال: 3/5 و 2/5 لهما نفس المقام 5. البسط 3 أكبر من 2، إذن:

3/5 > 2/5

انظر، الأجزاء كلّها متساوية ومن قسّم نفسه:

<svg viewBox="0 0 100 70"><rect x="10" y="8" width="80" height="22" fill="none" stroke="currentColor" stroke-width="2.5"/><rect x="10" y="8" width="48" height="22" fill="#d1d5db" stroke="currentColor" stroke-width="1.5"/><line x1="26" y1="8" x2="26" y2="30" stroke="currentColor" stroke-width="1.5"/><line x1="42" y1="8" x2="42" y2="30" stroke="currentColor" stroke-width="1.5"/><line x1="58" y1="8" x2="58" y2="30" stroke="currentColor" stroke-width="1.5"/><line x1="74" y1="8" x2="74" y2="30" stroke="currentColor" stroke-width="1.5"/><rect x="10" y="40" width="80" height="22" fill="none" stroke="currentColor" stroke-width="2.5"/><rect x="10" y="40" width="32" height="22" fill="#d1d5db" stroke="currentColor" stroke-width="1.5"/><line x1="26" y1="40" x2="26" y2="62" stroke="currentColor" stroke-width="1.5"/><line x1="42" y1="40" x2="42" y2="62" stroke="currentColor" stroke-width="1.5"/><line x1="58" y1="40" x2="58" y2="62" stroke="currentColor" stroke-width="1.5"/><line x1="74" y1="40" x2="74" y2="62" stroke="currentColor" stroke-width="1.5"/></svg>

الشريط الأعلى 3/5 (ملوّنٌ أكثر)، والأسفل 2/5. فعلًا 3/5 أكبر.

> ⚠️ انتبه: هذه القاعدة تصحّ **فقط حين يتساوى المقامان**. مقارنة كسرين بمقامين مختلفين (مثل 1/2 و 1/3) لها قاعدةٌ أخرى ستتعلّمها في السنة الخامسة. ومع ذلك تذكّر حدسيًّا أنّ **كلّما كثُرت الأجزاء صغُر كلُّ جزء**، فالثلث 1/3 أصغر من النصف 1/2، لا أكبر.

> 🏆 أحسنت أيّها البطل! صرت تفهم الكسر، وتميّز البسط من المقام، وتحسب الكسر من كمية، وتقارن كسرين بنفس المقام. في الفصل القادم — **قيس الأطوال** — ستستعمل هذه الأجزاء حين نقيس بأنصاف وأرباع المتر. تقدّم!', '# 📜 ملخّص: الكسور البسيطة

- **معنى الكسر**: نقسم الوحدة إلى **أجزاء متساوية**، والكسر عددٌ من هذه الأجزاء (الشرط: تساوي الأجزاء).
- **البسط والمقام**: نكتب الكسر **a/b**؛ المقام (تحت) = عدد الأجزاء كلّها، والبسط (فوق) = عدد الأجزاء المأخوذة. في 3/4: قسمنا إلى 4 وأخذنا 3.
- **لا تقلب الكسر**: «جزءان من 5» تُكتب 2/5 لا 5/2 (البسط فوق دائمًا).
- **الكسور المرجعية**: النصف 1/2 (جزء من جزأين)، الثلث 1/3 (جزء من 3)، الربع 1/4 (جزء من 4).
- **الأعشار**: تقسيم الوحدة إلى 10 أجزاء متساوية، كلّ جزءٍ عُشر = 1/10.
- **تمثيل الكسر بشكل**: نلوّن عددًا من الأجزاء المتساوية يساوي البسط من أصلٍ يساوي المقام.
- **الكسر من كمية**: اقسم الكمّية على **المقام** ثمّ اضرب في **البسط**. مثال: 1/4 من 12 = 12 ÷ 4 = 3.
- **مقارنة كسرين بنفس المقام**: الأجزاء متساوية الحجم، فالأكبر **بسطًا** هو الأكبر: 3/5 > 2/5.
- **تذكير حدسي**: كلّما كثُرت الأجزاء صغُر كلُّ جزء، فالثلث 1/3 أصغر من النصف 1/2.', 7)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('9501c37c-3d32-5963-8321-7c91daf390b6', 'math-4eme', 'قيس الأطوال', 'المتر (m) وحدةً مرجعية، مضاعفاته (km, hm, dam) وأجزاؤه (dm, cm, mm)، جدول الوحدات والعلاقات العشرية (1 km = 1 000 m ؛ 1 m = 10 dm = 100 cm = 1 000 mm)، التحويل بين الوحدات بالضرب أو القسمة على 10 و 100 و 1 000، اختيار الوحدة المناسبة لقيس شيء، جمع الأطوال وطرحها بنفس الوحدة وبعد التحويل، وحلّ مسائل في المسافات وأطوال الأضلاع', '# ⚔️ قيس الأطوال — سيّد الوحدات والتحويل

> 💡 «من يُتقن التحويل بين الوحدات، يقرأ كلّ مسافةٍ ويقيس كلّ شيءٍ بثقة.»

أهلًا أيّها البطل! تعلّمت في الفصل السابق **الكسور البسيطة**: كيف نأخذ جزءًا من وحدةٍ مجزّأة. اليوم سلاحٌ جديد: **قيس الأطوال**. كم يبعد بيتك عن المدرسة؟ كم يبلغ طول قلمك؟ لكلّ سؤالٍ **وحدةٌ مناسبة**. في هذه المغامرة نتعرّف على وحدات الطول كلّها، ونبني **جدول الوحدات**، ونتعلّم **التحويل** بينها، ثمّ نجمع الأطوال ونطرحها ونحلّ بها مسائل.

## 📏 المتر: الوحدة المرجعيّة

الوحدة الأساسيّة لقيس الأطوال هي **المتر (m)**. كلّ الوحدات الأخرى تُبنى انطلاقًا منه: بعضها **أكبر** من المتر (المضاعفات)، وبعضها **أصغر** منه (الأجزاء).

- *مثال على المتر:* عرض البابِ تقريبًا 1 m، وطول معلّمك حوالى 2 m.

## ⚡ مضاعفات المتر وأجزاؤه

نكبّر أو نصغّر الوحدة بالضرب أو القسمة على **10** في كلّ مرّة. هذا **جدول الوحدات** من الأكبر إلى الأصغر:

| الوحدة | الرمز | بالنسبة إلى المتر |
| ------ | ----- | ----------------- |
| كيلومتر | km | 1 km = 1 000 m |
| هكتومتر | hm | 1 hm = 100 m |
| ديكامتر | dam | 1 dam = 10 m |
| **متر** | **m** | الوحدة المرجعيّة |
| ديسيمتر | dm | 1 m = 10 dm |
| صنتيمتر | cm | 1 m = 100 cm |
| مليمتر | mm | 1 m = 1 000 mm |

- **الكيلومتر (km)** للمسافات الكبيرة: المسافة بين مدينتين.
- **المتر (m)** للأطوال المتوسّطة: طول غرفةٍ أو ملعب.
- **الصنتيمتر (cm)** و**المليمتر (mm)** للأطوال الصغيرة: طول قلمٍ أو سُمك ورقة.

> 🗡️ احفظ العلاقات المرجعيّة الأربع: 1 km = 1 000 m، و 1 m = 10 dm = 100 cm = 1 000 mm.

## 🔮 العلاقات العشريّة بين الوحدات

كلّما **نزلنا** درجةً في الجدول (نحو الأصغر) **نضرب في 10**، وكلّما **صعدنا** درجةً (نحو الأكبر) **نقسم على 10**. إذن بين وحدتين تفصلهما درجتان نضرب أو نقسم على **100**، وبين ثلاث درجات على **1 000**.

$$1 m = 10 dm = 100 cm = 1 000 mm$$

- *من m إلى cm:* درجتان نحو الأسفل ← نضرب في 100.
- *من mm إلى m:* ثلاث درجات نحو الأعلى ← نقسم على 1 000.

## 🧮 التحويل بين الوحدات

**القاعدة الذهبيّة:** للتحويل إلى وحدةٍ **أصغر** نضرب (في 10 أو 100 أو 1 000)، وللتحويل إلى وحدةٍ **أكبر** نقسم.

*مثال محسوب 1 — من الكبير إلى الصغير:* حوّل 5 m إلى cm.
المتر أكبر، والصنتيمتر أصغر بدرجتين، فنضرب في 100:
5 × 100 = 500 → **5 m = 500 cm**.

*مثال محسوب 2 — من الصغير إلى الكبير:* حوّل 3 000 m إلى km.
المتر أصغر، والكيلومتر أكبر بثلاث درجات، فنقسم على 1 000:
3 000 ÷ 1 000 = 3 → **3 000 m = 3 km**.

*مثال محسوب 3:* حوّل 4 km إلى m: 4 × 1 000 = 4 000 → **4 km = 4 000 m**.

> ⚠️ احذر الفخّ! عدد الأصفار يدلّ على العملية. من m إلى cm نضرب في **100** (صفران) وليس في 10: فـ 2 m = 200 cm وليس 20 cm.

## 🛡️ اختيار الوحدة المناسبة

لكلّ شيءٍ وحدةٌ يُناسب قيسها به، فلا نقيس مسافةً بين مدينتين بالمليمتر ولا سُمك ورقةٍ بالكيلومتر.

| ما نقيسه | الوحدة المناسبة |
| -------- | ---------------- |
| المسافة بين مدينتين | km |
| طول ملعبٍ أو غرفة | m |
| طول كتابٍ أو قلم | cm |
| سُمك ورقةٍ أو عملة | mm |

## 🧪 جمع الأطوال وطرحها وحلّ المسائل

لا نجمع الأطوال أو نطرحها إلّا إذا كانت **بنفس الوحدة**. إن اختلفت الوحدتان، **نحوّل أوّلًا** إلى وحدةٍ واحدة، ثمّ نحسب.

*مثال محسوب 4 — بنفس الوحدة:* محيط مثلّثٍ أضلاعه 15 cm و 20 cm و 25 cm.
نجمع: 15 + 20 + 25 = 60 → **المحيط = 60 cm**.

*مثال محسوب 5 — بعد التحويل:* شريطٌ طوله 2 m، قُطع منه 40 cm. كم بقي؟
نوحّد الوحدة: 2 m = 200 cm، ثمّ نطرح: 200 − 40 = 160 → **بقي 160 cm**.

> 🗡️ في أيّ مسألةٍ فيها وحدتان مختلفتان، ابدأ دائمًا **بالتوحيد** قبل الجمع أو الطرح، وإلّا كان الجواب خاطئًا.

> 🏆 أحسنت أيّها البطل! صرت تعرف وحدات الطول كلّها (km, hm, dam, m, dm, cm, mm)، وتبني جدول الوحدات، وتحوّل بينها بالضرب أو القسمة على 10 و 100 و 1 000، وتجمع الأطوال وتطرحها وتحلّ بها المسائل. استعدّ الآن لمغامرتك القادمة: **قيس الكتل**!', '# 📜 ملخّص: قيس الأطوال

- **الوحدة المرجعيّة** لقيس الأطوال هي **المتر (m)**؛ منه تُبنى بقيّة الوحدات.
- **جدول الوحدات** من الأكبر إلى الأصغر: km، hm، dam، **m**، dm، cm، mm (نضرب أو نقسم على 10 بين كلّ درجتين متجاورتين).
- **العلاقات المرجعيّة:** 1 km = 1 000 m، و 1 m = 10 dm = 100 cm = 1 000 mm.
- **التحويل:** إلى وحدةٍ **أصغر** نضرب (في 10 أو 100 أو 1 000)، وإلى وحدةٍ **أكبر** نقسم. مثال: 5 m = 500 cm، و 3 000 m = 3 km.
- **عدد الأصفار يدلّ على العملية:** من m إلى cm نضرب في **100** لا في 10، فـ 2 m = 200 cm.
- **اختيار الوحدة:** km للمسافات بين المدن، m للغرف والملاعب، cm للكتب والأقلام، mm لسُمك الورق.
- **الجمع والطرح** لا يصحّان إلّا **بنفس الوحدة**؛ إن اختلفت الوحدتان **نحوّل أوّلًا** ثمّ نحسب: 2 m − 40 cm = 200 cm − 40 cm = 160 cm.
- **حلّ المسائل:** محيط شكلٍ = مجموع أطوال أضلاعه بنفس الوحدة (15 + 20 + 25 = 60 cm).', 8)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('78a5dfbe-4c9b-5f48-8161-13ea1f5c3d79', 'math-4eme', 'قيس الكتل', 'قيس الكتل بالكيلوغرام (kg) والغرام (g) والطن (t)، والعلاقتان 1 kg = 1000 g و 1 t = 1000 kg، التحويل بين الوحدات، الكتل المرجعيّة (نصف كيلو = 500 g، ربع كيلو = 250 g)، اختيار الوحدة المناسبة، قراءة كتلةٍ على الميزان، وجمع الكتل وطرحها وحلّ مسائل (الكتلة الصافية والقائمة)', '# ⚔️ قيس الكتل — مغامرة الميزان والكنوز الثقيلة

> 💡 «من يُتقن الميزان يَعرف وزن كلّ شيء: من حبّة قمحٍ إلى شاحنةٍ محمّلة.»

أهلًا بك أيّها البطل! في الفصل السابق تعلّمت **قيس الأطوال** بالمتر والصنتيمتر. اليوم نتعلّم سلاحًا جديدًا: **قيس الكتل**، أي كم يَزِن الشيء. ستحتاجه في السوق، في المطبخ، وكلّما اشتريت شيئًا يُوزَن.

## ⚖️ ما هي الكتلة وبأيّ شيء نقيسها؟

**الكتلة** هي مقدار ما يَزِنه الشيء: هل هو خفيفٌ أم ثقيل؟ نقيس الكتلة بأداةٍ اسمها **الميزان**.

عندنا ثلاث وحداتٍ أساسيّة، من الأصغر إلى الأكبر:

| الوحدة | الرمز | نقيس بها | مثال |
| --- | --- | --- | --- |
| الغرام | g | الأشياء الخفيفة جدًّا | حبّة لوز، ريشة |
| الكيلوغرام | kg | المشتريات اليوميّة | كيس سكّر، بطّيخة |
| الطنّ | t | الأشياء الثقيلة جدًّا | سيّارة، شاحنة |

> 🗡️ القاعدة البسيطة: كلّما كان الشيء **أثقل**، اخترنا وحدةً **أكبر**. التفّاحة بالـ g، كيس الطحين بالـ kg، الفيل بالـ t.

## 🔗 العلاقات بين الوحدات

هاتان العلاقتان هما مفتاح الفصل كلّه، احفظهما جيّدًا:

$$1 kg = 1000 g$$

$$1 t = 1000 kg$$

أي أنّ كلّ كيلوغرامٍ فيه **1 000** غرام، وكلّ طنٍّ فيه **1 000** كيلوغرام.

*مثال محسوب:* كم غرامًا في 3 kg؟ نضرب في 1000: 3 × 1000 = 3000. إذن 3 kg = 3 000 g.

## 🔮 التحويل بين الوحدات

للتحويل نستعمل قاعدتين متعاكستين:

- **من الوحدة الكبيرة إلى الصغيرة → نضرب في 1000** (kg ← g، أو t ← kg).
- **من الوحدة الصغيرة إلى الكبيرة → نقسم على 1000** (g ← kg، أو kg ← t).

*مثال 1:* حوّل 5 kg إلى غرامات. نضرب: 5 × 1000 = 5000. إذن 5 kg = 5 000 g.

*مثال 2:* حوّل 4 000 g إلى كيلوغرامات. نقسم: 4000 ÷ 1000 = 4. إذن 4 000 g = 4 kg.

*مثال 3:* حوّل 2 t إلى كيلوغرامات. نضرب: 2 × 1000 = 2000. إذن 2 t = 2 000 kg.

> ⚠️ احذر الفخّ! للتحويل بين kg و g نضرب (أو نقسم) في **1000** وليس في 100. فالعدد 2 kg يساوي 2 000 g وليس 200 g.

## 🛡️ الكتل المرجعيّة: نصف كيلو وربع كيلو

في السوق نسمع كثيرًا «نصف كيلو» و«ربع كيلو». هذه **كتلٌ مرجعيّة** يجب أن تحفظها:

- **نصف كيلو** = نصف الـ 1000 g = **500 g**.
- **ربع كيلو** = ربع الـ 1000 g = **250 g**.

*مثال محسوب:* اشترت أمّي نصف كيلو لحمٍ وربع كيلو زيتون. كم غرامًا في المجموع؟ 500 + 250 = 750. إذن المجموع 750 g.

> 🗡️ تذكّر: النصف أكبر من الربع. 500 g (نصف كيلو) أثقل من 250 g (ربع كيلو).

## 🧮 جمع الكتل وطرحها

لكي نجمع كتلتين أو نطرحهما، يجب أن تكونا **بنفس الوحدة**، ثمّ نجري العمليّة على الأعداد.

- *جمع:* كيس فيه 2 kg تفّاح وكيس فيه 3 kg برتقال. الكتلة كلّها: 2 + 3 = 5، أي 5 kg.
- *طرح:* في الكيس 6 kg طحين، استعملنا منه 2 kg. الباقي: 6 − 2 = 4، أي 4 kg.

أحيانًا نحتاج إلى **توحيد الوحدة** أوّلًا: لجمع 1 kg و 500 g، نحوّل 1 kg = 1000 g، ثمّ 1000 + 500 = 1500، أي 1 500 g.

## 🧪 الكتلة الصافية والكتلة القائمة

عند بيع البضائع نميّز بين ثلاث كتل:

- **الكتلة الصافية** هي كتلة البضاعة وحدها (المحتوى).
- **كتلة الوعاء** هي كتلة العلبة أو الكيس الفارغ.
- **الكتلة القائمة** هي كتلة البضاعة **مع** وعائها معًا.

العلاقة بينها:

$$الكتلة القائمة = الكتلة الصافية + كتلة الوعاء$$

*مثال محسوب:* علبة بسكويتٍ صافيها 400 g، والعلبة الفارغة كتلتها 100 g. الكتلة القائمة: 400 + 100 = 500، أي 500 g. وللعكس، إذا عرفنا القائمة (500 g) وكتلة الوعاء (100 g)، فالصافية: 500 − 100 = 400، أي 400 g.

> 🏆 أحسنت أيّها البطل! صرت تعرف الوحدات g و kg و t، والعلاقتين 1 kg = 1000 g و 1 t = 1000 kg، وتحوّل بينها، وتحفظ نصف كيلو (500 g) وربع كيلو (250 g)، وتجمع الكتل وتطرحها وتميّز الصافية من القائمة. خذ ميزانك واستعدّ للتحدّي… وفي الفصل القادم نقيس **السعة** (اللتر)! 🏆', '# 📜 ملخّص: قيس الكتل

- **الكتلة** هي وزن الشيء، ونقيسها بـ **الميزان**.
- **الوحدات** من الأصغر إلى الأكبر: الغرام **g**، الكيلوغرام **kg**، الطنّ **t**.
- **العلاقتان الأساسيّتان**: 1 kg = 1000 g و 1 t = 1000 kg.
- **التحويل**: من الكبيرة إلى الصغيرة نضرب في 1000 (5 kg = 5 000 g)؛ ومن الصغيرة إلى الكبيرة نقسم على 1000 (3 000 g = 3 kg).
- **اختيار الوحدة**: الخفيف بالـ g، المشتريات بالـ kg، الثقيل جدًّا بالـ t.
- **الكتل المرجعيّة**: نصف كيلو = 500 g، وربع كيلو = 250 g.
- **جمع وطرح الكتل**: يجب توحيد الوحدة أوّلًا، ثمّ نجمع أو نطرح الأعداد (2 kg + 3 kg = 5 kg).
- **الكتلة القائمة = الكتلة الصافية + كتلة الوعاء** (الصافية = القائمة − كتلة الوعاء).
- **الفخّ الشائع**: بين kg و g نضرب في 1000 وليس في 100 (2 kg = 2 000 g).', 9)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('b6209606-1ac5-5cef-9bbf-99560f442101', 'math-4eme', 'قيس السعة', 'قيس السعة باللتر (L) وأجزائه (dL، cL، mL) ومضاعفاته، والعلاقات العشرية 1 L = 10 dL = 100 cL = 1000 mL، التحويل بين الوحدات، السعات المرجعيّة (نصف لتر = 50 cL = 500 mL، ربع لتر = 25 cL = 250 mL)، اختيار الوحدة المناسبة، وجمع السعات وطرحها وحلّ مسائل (قوارير وعصير وصهريج)', '# ⚔️ قيس السعة — مغامرة اللتر والقارورة

> 💡 «من يَعرف السعة، يَعرف كم يَملأ القارورة وكم يَكفي العصير للجميع.»

أهلًا بك أيّها البطل! تعلّمتَ في المغامرة السابقة كيف **تقيس الكتل** بالكيلوغرام والغرام. اليوم نتعلّم سلاحًا جديدًا: **قيس السعة** — أي كم من السائل (ماء، عصير، حليب) يَملأ إناءً. وحدتنا المرجعيّة هي **اللتر**.

## 🏰 ما هي السعة؟ اللتر وحدةً مرجعيّة

**السعة** هي مقدار ما يَملأ إناءً من سائل. نقيسها بوحدةٍ مرجعيّة اسمها **اللتر**، ورمزها **L**.

- قارورة الماء الكبيرة سعتها قريبة من **1 L**.
- علبة العصير الصغيرة سعتها أقلّ من اللتر، فنحتاج **وحدات أصغر**.
- الصهريج أو الخزّان سعته كبيرة، فنحتاج **وحدات أكبر** أو عددًا كبيرًا من اللترات.

لذلك للّتر **أجزاء** (وحدات أصغر منه) و**مضاعفات** (وحدات أكبر منه)، تمامًا كما للمتر وللكيلوغرام.

## 🔮 أجزاء اللتر: dL و cL و mL

عندما يكون السائل قليلًا، نقيسه بأجزاء اللتر. هذه أهمّ ثلاثة أجزاء:

| الوحدة | الرمز | كم في اللتر الواحد |
| --- | --- | --- |
| الدّيسيلتر | dL | 1 L = 10 dL |
| الصّنتيلتر | cL | 1 L = 100 cL |
| المليلتر | mL | 1 L = 1000 mL |

العلاقات العشريّة كاملةً في سلسلةٍ واحدة، احفظها جيّدًا:

$$1 L = 10 dL = 100 cL = 1000 mL$$

*مثال محسوب:* ملعقة دواء سعتها 5 mL، وكوب صغير سعته 20 cL، وقارورة سعتها 1 L. كلّما صغُر الإناء، اخترنا وحدةً أصغر.

> 🗡️ لاحظ السُّلّم: من اللتر إلى mL نضرب في **1000**، ومن اللتر إلى cL نضرب في **100**، ومن اللتر إلى dL نضرب في **10**. العلاقات **عشريّة** (10، 100، 1000) كما في الأطوال والكتل.

## 🧮 التحويل بين الوحدات

للتحويل من وحدةٍ **كبيرة** إلى وحدةٍ **أصغر**، نضرب. وللعكس، من وحدةٍ **صغيرة** إلى وحدةٍ **أكبر**، نقسم.

- من L إلى mL: نضرب في 1000. مثلًا: 3 L = 3 × 1000 = 3 000 mL.
- من L إلى cL: نضرب في 100. مثلًا: 2 L = 2 × 100 = 200 cL.
- من mL إلى L: نقسم على 1000. مثلًا: 5 000 mL = 5 000 ÷ 1000 = 5 L.
- من cL إلى L: نقسم على 100. مثلًا: 400 cL = 400 ÷ 100 = 4 L.

أحيانًا نكتب السعة بوحدتين معًا: 1 500 mL = 1 000 mL + 500 mL = **1 L و 500 mL**.

> ⚠️ احذر الفخّ! لا تَخلط بين **cL** و**mL**. اللتر فيه 100 cL لكنّه فيه 1000 mL. إذن 1 cL = 10 mL، وليس 1 cL = 1 mL.

## 🧪 السعات المرجعيّة: نصف لتر وربع لتر

هناك سعتان نراهما كثيرًا في الحياة، احفظهما عن ظهر قلب:

| السعة | بالـ cL | بالـ mL |
| --- | --- | --- |
| نصف لتر | 50 cL | 500 mL |
| ربع لتر | 25 cL | 250 mL |

*كيف نجدهما؟* نصف اللتر = نصف 1000 mL = **500 mL**، وهو نصف 100 cL = **50 cL**. وربع اللتر = ربع 1000 mL = **250 mL**، وهو ربع 100 cL = **25 cL**.

علبة العصير الصغيرة غالبًا سعتها **ربع لتر** (250 mL)، وقارورة الحليب المتوسّطة سعتها **نصف لتر** (500 mL).

> ⚠️ نصف اللتر يساوي **500 mL** وليس 50 mL، وربع اللتر يساوي **250 mL** وليس 25 mL. الخطأ الشائع هو الخلط بين mL و cL هنا.

## 🛡️ اختيار الوحدة المناسبة

نختار الوحدة حسب حجم الإناء، حتّى يكون العدد بسيطًا ومعقولًا:

- **mL** للكمّيّات الصغيرة جدًّا: ملعقة دواء، قطرات، أمبولة.
- **cL** أو **dL** للأكواب والعلب الصغيرة.
- **L** للقوارير والدِّلاء.
- **مضاعفات اللتر** (عدد كبير من اللترات) للصهاريج والخزّانات: صهريج فيه 1 000 L مثلًا.

*مثال:* لقياس سعة ملعقةٍ نختار mL، ولقياس سعة برميلٍ نختار L. لو قِسنا الملعقة باللتر لكان العدد صغيرًا جدًّا وغير مريح.

## 📐 العمليّات على السعات وحلّ المسائل

لجمع سعتين أو طرحهما، يجب أن تكونا **بنفس الوحدة**، ثمّ نُجري العمليّة على العددين.

- جمع: 30 cL + 20 cL = 50 cL.
- طرح: قارورة فيها 1 L = 1 000 mL، شربنا 400 mL، فالباقي 1 000 − 400 = 600 mL.

*مسألة محلولة:* صهريج سعته 500 L، فُرِّغ منه 200 L. كم بقي؟ نطرح بنفس الوحدة: 500 − 200 = 300. إذن بقي **300 L**.

> 🗡️ قبل الجمع أو الطرح، وحِّد الوحدة أوّلًا. لجمع 1 L مع 200 mL، حوّل اللتر: 1 L = 1 000 mL، ثمّ 1 000 + 200 = 1 200 mL.

> 🏆 أحسنتَ أيّها البطل! صرتَ تَقيس السعة باللتر وأجزائه (dL، cL، mL)، وتعرف أنّ 1 L = 1000 mL، وتُحوّل بين الوحدات، وتُتقن نصف اللتر وربعه، وتجمع السعات وتطرحها. في المغامرة القادمة ننتقل إلى **النقود: الدينار والمليم** لنتعلّم البيع والشراء!', '# 📜 ملخّص: قيس السعة

- **السعة** مقدار ما يَملأ إناءً من سائل، ووحدتها المرجعيّة **اللتر (L)**.
- **أجزاء اللتر**: الدّيسيلتر (dL)، الصّنتيلتر (cL)، المليلتر (mL).
- العلاقات العشريّة كاملةً: **1 L = 10 dL = 100 cL = 1000 mL**.
- **التحويل**: من L إلى mL نضرب في 1000 (3 L = 3 000 mL)؛ من mL إلى L نقسم على 1000 (5 000 mL = 5 L).
- **انتبه**: 1 cL = 10 mL (لا تَخلط cL مع mL).
- **نصف لتر** = 50 cL = **500 mL**، و**ربع لتر** = 25 cL = **250 mL**.
- **اختيار الوحدة**: mL للملعقة، cL/dL للكوب، L للقارورة، مضاعفات اللتر للصهريج.
- **الجمع والطرح**: وحِّد الوحدة أوّلًا ثمّ أَجرِ العمليّة: 1 L − 400 mL = 1 000 − 400 = 600 mL.', 10)
