INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('456a1869-dedc-5271-93ff-1b42631ac49c', '7248ab16-f92a-533a-9836-4ae0ce003d93', 'أنا عددٌ من أربعة أرقام: رقمُ آلافي 6، ورقمُ مئاتي صفر، ورقمُ عشراتي صفر، ورقمُ آحادي 9. من أكون؟', '[{"id":"a","text":"6 900"},{"id":"b","text":"6 090"},{"id":"c","text":"69"},{"id":"d","text":"6 009"}]'::jsonb, 'd', 'نضع كلّ رقمٍ في رتبته: 6 آلاف، 0 مئات، 0 عشرات، 9 آحاد، فيكون العدد 6 009. الخطأ الشائع هو نسيان أحد الصفرين فيُكتب 69 أو 6 090.', 1)
