INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1d01dd8-83d0-5004-88eb-479f89f748f0', '7248ab16-f92a-533a-9836-4ae0ce003d93', 'باستعمال الأرقام 4 و 0 و 8 و 1 مرّةً واحدة لكلٍّ منها، ما أصغر عددٍ من أربعة أرقام يمكن تكوينه؟', '[{"id":"a","text":"0 148"},{"id":"b","text":"1 048"},{"id":"c","text":"1 084"},{"id":"d","text":"8 410"}]'::jsonb, 'b', 'لا يجوز أن يبدأ العدد بالصفر وإلّا صار من ثلاثة أرقام، فنضع 1 (أصغر رقمٍ غير الصفر) في الآلاف، ثمّ 0 في المئات، ثمّ 4، ثمّ 8: 1 048. الخطأ الشائع هو وضع الصفر في رتبة الآلاف.', 2)
ON CONFLICT (id) DO UPDATE SET
