INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d644f959-eea8-5d95-a959-6532c08d8075', '2472a4bb-fe42-5e82-82f1-246187df2ecd', 'أنا عددٌ من خمسة أرقام: رقمُ عشرات آلافي 4، ورقمُ آلافي 0، وصنفُ وحداتي 207. من أكون؟', '[{"id":"a","text":"40 207"},{"id":"b","text":"4 207"},{"id":"c","text":"42 070"},{"id":"d","text":"40 027"}]'::jsonb, 'a', 'نضع 4 في عشرات الآلاف، و 0 في الآلاف، ثمّ صنف الوحدات 207، فيكون العدد 40 207.', 1)
