INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08a67320-40a6-56ed-ae4f-a081b60f36e8', '2472a4bb-fe42-5e82-82f1-246187df2ecd', 'باستعمال الأرقام 8 و 3 و 0 و 5 و 1 مرّةً واحدة لكلٍّ منها، ما أكبر عددٍ من خمسة أرقام يمكن تكوينه؟', '[{"id":"a","text":"85 310"},{"id":"b","text":"85 301"},{"id":"c","text":"83 510"},{"id":"d","text":"58 310"}]'::jsonb, 'a', 'لتكوين أكبر عددٍ نرتّب الأرقام تنازليًّا من أعلى رتبة: 8 ثمّ 5 ثمّ 3 ثمّ 1 ثمّ 0، فنحصل على 85 310.', 2)
