INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f1b3ac1-f517-50c0-9f92-8bc6bfad2a64', '2472a4bb-fe42-5e82-82f1-246187df2ecd', 'باستعمال الأرقام 8 و 3 و 0 و 5 و 1 مرّةً واحدة لكلٍّ منها، ما أصغر عددٍ من خمسة أرقام يمكن تكوينه؟', '[{"id":"a","text":"01 358"},{"id":"b","text":"10 358"},{"id":"c","text":"13 058"},{"id":"d","text":"10 385"}]'::jsonb, 'b', 'لا يجوز أن يبدأ العدد بالصفر وإلّا صار من أربعة أرقام، فنضع 1 (أصغر رقمٍ غير الصفر) في عشرات الآلاف، ثمّ نرتّب الباقي تصاعديًّا: 0 ثمّ 3 ثمّ 5 ثمّ 8، فنحصل على 10 358.', 3)
