INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e4e38356-37b7-5721-8e79-58a9e11fb509', '733b60fd-e42e-5cb5-859d-19cc2dcf4741', 'أنا عددٌ من ستّة أرقام: صنفُ آلافي 250 وصنفُ وحداتي 007. من أكون؟', '[{"id":"a","text":"250 700"},{"id":"b","text":"250 007"},{"id":"c","text":"25 007"},{"id":"d","text":"257 000"}]'::jsonb, 'b', 'صنف الآلاف 250 يُكتب في الرتب الثلاث العليا، وصنف الوحدات 007 في الرتب الثلاث الدنيا، فيكون العدد 250 007. الأصفار في المئات والعشرات تحفظ المكان.', 1)
