INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('652dbb32-021b-5beb-890c-abde20ce3731', '733b60fd-e42e-5cb5-859d-19cc2dcf4741', 'باستعمال الأرقام 6 و 0 و 3 و 1 و 0 و 5 مرّةً واحدة لكلٍّ منها، ما أصغر عددٍ من ستّة أرقامٍ يمكن تكوينه؟', '[{"id":"a","text":"013 560"},{"id":"b","text":"100 356"},{"id":"c","text":"103 560"},{"id":"d","text":"103 056"}]'::jsonb, 'd', 'لا يجوز أن يبدأ العدد بالصفر، فنضع أصغر رقمٍ غير الصفر (1) في مئات الآلاف، ثمّ نرتّب الباقي تصاعديًّا 0 ثمّ 0 ثمّ 3 ثمّ 5 ثمّ 6: 103 056. الخطأ الشائع البدء بالصفر فيصير العدد من خمسة أرقام.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07ecd230-f050-58b9-b3d9-f121e9dda7cc', '733b60fd-e42e-5cb5-859d-19cc2dcf4741', 'كم تزيد قيمة الرقم 4 في العدد 400 000 عنها في العدد 040 000؟ (نعني العدد 40 000)', '[{"id":"a","text":"متساويتان"},{"id":"b","text":"360 000"},{"id":"c","text":"440 000"},{"id":"d","text":"40 000"}]'::jsonb, 'b', 'في 400 000 الرقم 4 في مئات الآلاف فقيمته 400 000؛ وفي 40 000 الرقم 4 في عشرات الآلاف فقيمته 40 000. الفرق 400 000 − 40 000 = 360 000.', 3)
