  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d60cdbd-9835-5486-af6a-ac0413a0f658', '733b60fd-e42e-5cb5-859d-19cc2dcf4741', 'أنا أكبر عددٍ من ستّة أرقامٍ كلُّ أرقامه مختلفة ورقمُ آحاده 0. من أكون؟', '[{"id":"a","text":"987 650"},{"id":"b","text":"999 990"},{"id":"c","text":"987 654"},{"id":"d","text":"986 750"}]'::jsonb, 'a', 'لأكبر عددٍ بأرقامٍ مختلفة نرتّب أكبر الأرقام تنازليًّا من اليسار، لكنّ آحاده مفروضةٌ أن تكون 0؛ فنضع 9 و 8 و 7 و 6 و 5 في الرتب العليا و 0 في الآحاد: 987 650. الخطأ الشائع تكرار الرقم 9 رغم شرط الاختلاف.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d6611c6-08e9-5331-8e2c-b9d1214796ec', '733b60fd-e42e-5cb5-859d-19cc2dcf4741', 'أنا عددٌ من ستّة أرقام: رقمُ مئات آلافي 6، ورقمُ آلافي يساوي رقمَ مئات آلافي، وبقيّةُ أرقامي أصفار. من أكون؟', '[{"id":"a","text":"660 000"},{"id":"b","text":"600 600"},{"id":"c","text":"606 000"},{"id":"d","text":"600 060"}]'::jsonb, 'c', 'رقم مئات الآلاف 6، ورقم الآلاف يساويه فهو 6، وعشرات الآلاف والمئات والعشرات والآحاد أصفار، فيكون العدد 606 000.', 5)
ON CONFLICT (id) DO UPDATE SET
