  ('78cda3ad-7e15-56be-aff1-a6f3ab8deec9', '733b60fd-e42e-5cb5-859d-19cc2dcf4741', 'العدد 8 _ 5 432 من ستّة أرقام؛ ما الرقم في الفراغ (رتبة عشرات الآلاف) ليكون العدد محصورًا بين 800 000 و 810 000؟', '[{"id":"a","text":"1"},{"id":"b","text":"5"},{"id":"c","text":"0"},{"id":"d","text":"8"}]'::jsonb, 'c', 'ليكون العدد بين 800 000 و 810 000 يجب أن تكون رتبة عشرات الآلاف 0، فيصير العدد 805 432 وهو محصورٌ بينهما. أيّ رقمٍ أكبر من 0 يجعل العدد أكبر من 810 000.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
