INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7ccc7923-7cbb-5566-b095-f87bb215def9', '62deb5db-c8f7-56a3-a9a9-15eacd0f7a88', 'في العمليّة 38 − 13 = 25، ماذا نسمّي العدد 25؟', '[{"id":"a","text":"المطروح منه"},{"id":"b","text":"المطروح"},{"id":"c","text":"الفرق"},{"id":"d","text":"المجموع"}]'::jsonb, 'c', 'في الطرح: المطروح منه − المطروح = الفرق. فالعدد 38 هو المطروح منه، و 13 هو المطروح، و 25 هو الفرق (نتيجة الطرح).', 1)
