  ('9653d66e-93f8-5ca2-914d-3d1cd1a5b8b9', '7d7c795d-3aea-50d6-82f2-bd3a02e48c0b', 'في مخزنٍ 250 000 قطعة. خرجت شحنةٌ أولى 85 600 قطعة وشحنةٌ ثانية 92 400 قطعة. كم قطعةً بقيت في المخزن؟', '[{"id":"a","text":"82 000"},{"id":"b","text":"71 000"},{"id":"c","text":"72 000"},{"id":"d","text":"178 000"}]'::jsonb, 'c', 'مسألة بعمليّتين: نجمع الشحنتين 85 600 + 92 400 = 178 000، ثمّ نطرح من المخزون 250 000 − 178 000 = 72 000 قطعة. الخيار (د) خطأ لأنّه مجموع الخارج لا الباقي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
