  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('39dbc09e-87a7-59d9-8152-0aa41cf32a68', '7d7c795d-3aea-50d6-82f2-bd3a02e48c0b', 'أراد تلميذ أن يحسب 123 456 + 88 544. أيّ نتيجةٍ هي الصحيحة، وما الخطأ الشائع الذي يقع فيه كثيرون؟', '[{"id":"a","text":"212 000"},{"id":"b","text":"211 900 (نسي احتفاظًا)"},{"id":"c","text":"201 990"},{"id":"d","text":"212 900"}]'::jsonb, 'a', 'الآحاد 6 + 4 = 10 نحتفظ بـ 1؛ العشرات 5 + 4 + 1 = 10 نحتفظ بـ 1؛ المئات 4 + 5 + 1 = 10 نحتفظ بـ 1؛ الآلاف 3 + 8 + 1 = 12 نحتفظ بـ 1؛ عشرات الآلاف 2 + 8 + 1 = 11 نحتفظ بـ 1؛ مئات الآلاف 1 + 1 = 2، فالصواب 212 000. الخطأ الشائع نسيان أحد المحتفَظ بها في سلسلة الأصفار فينقص المجموع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

