  ('03231423-e404-5ec8-8245-86130ff09b51', 'c2bc2690-d2f8-5888-af55-a9c139bcdfe4', 'كم يساوي 67 890 + 23 456؟', '[{"id":"a","text":"90 346"},{"id":"b","text":"91 346"},{"id":"c","text":"91 246"},{"id":"d","text":"91 356"}]'::jsonb, 'b', 'الآحاد 0 + 6 = 6؛ العشرات 9 + 5 = 14 نحتفظ بـ 1؛ المئات 8 + 4 + 1 = 13 نحتفظ بـ 1؛ الآلاف 7 + 3 + 1 = 11 نحتفظ بـ 1؛ عشرات الآلاف 6 + 2 + 1 = 9، فيكون المجموع 91 346.', 1)
