INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19bc51a3-7ab3-5034-a069-084c013784d0', 'c2bc2690-d2f8-5888-af55-a9c139bcdfe4', 'نعلم أنّ 25 + (75 + 48) = 148. فكم يساوي (25 + 75) + 48؟', '[{"id":"a","text":"138"},{"id":"b","text":"158"},{"id":"c","text":"100"},{"id":"d","text":"148"}]'::jsonb, 'd', 'حسب خاصيّة التجميعيّة، طريقة تجميع الحدود لا تغيّر المجموع، فإنّ (25 + 75) + 48 = 25 + (75 + 48) = 148.', 2)
