  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab5edb13-5e6f-5e48-a6e9-d212b3b0c4c8', 'c2bc2690-d2f8-5888-af55-a9c139bcdfe4', 'ما العدد المفقود؟  ‏... + 3600 = 9000', '[{"id":"a","text":"5400"},{"id":"b","text":"6400"},{"id":"c","text":"5300"},{"id":"d","text":"12 600"}]'::jsonb, 'a', 'لإيجاد حدٍّ مفقود في جمع نطرح المعلوم من المجموع: 9000 − 3600 = 5400. تثبّت: 5400 + 3600 = 9000 ✓.', 3)
