INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('587219ed-a2d2-5e45-9958-e9d2a0c4c9e1', '0af74aa2-3495-5976-acd4-0a345eac83ca', 'في القسمة على 7، ما هو أكبر باقٍ ممكن؟', '[{"id":"a","text":"7"},{"id":"b","text":"8"},{"id":"c","text":"6"},{"id":"d","text":"1"}]'::jsonb, 'c', 'الباقي دائمًا أصغر من المقسوم عليه، فأكبر باقٍ عند القسمة على 7 هو 6. الخطأ الشائع 7: لو كان الباقي 7 لأمكن أخذ 7 مرّةً أخرى وزيادة الخارج.', 1)
