INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('495e6caf-017e-57b6-b903-f994f731d5c4', '0af74aa2-3495-5976-acd4-0a345eac83ca', 'ما خارج القسمة 125 ÷ 4؟', '[{"id":"a","text":"30"},{"id":"b","text":"31"},{"id":"c","text":"32"},{"id":"d","text":"21"}]'::jsonb, 'b', 'منصوبًا: 12 ÷ 4 = 3 والباقي 0، ننزّل 5 فنحصل 5، و 5 ÷ 4 = 1 والباقي 1. الخارج 31 والباقي 1. نتحقّق: (4 × 31) + 1 = 125 ✓.', 2)
