  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4db5aacc-7efc-54f5-af8e-09eed99fb3d2', '0af74aa2-3495-5976-acd4-0a345eac83ca', 'عند المزارع 50 بيضة يضعها في علبٍ سعةُ كلٍّ منها 6 بيضات. كم علبةً كاملةً يملأ؟', '[{"id":"a","text":"6"},{"id":"b","text":"7"},{"id":"c","text":"9"},{"id":"d","text":"8"}]'::jsonb, 'd', 'تجميع: 50 ÷ 6 = 8 والباقي 2 لأنّ (6 × 8) + 2 = 50. يملأ 8 علبٍ كاملة وتبقى 2 بيضتان لا تكفيان لعلبةٍ جديدة.', 3)
