INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d329706-9f6e-5e09-abf1-8d1a16c52f21', '0af74aa2-3495-5976-acd4-0a345eac83ca', 'ما خارج القسمة 7488 ÷ 6؟', '[{"id":"a","text":"1238"},{"id":"b","text":"1248"},{"id":"c","text":"1284"},{"id":"d","text":"1148"}]'::jsonb, 'b', 'منصوبًا من اليسار: 7 ÷ 6 = 1 والباقي 1، ننزّل 4 فـ 14 ÷ 6 = 2 والباقي 2، ننزّل 8 فـ 28 ÷ 6 = 4 والباقي 4، ننزّل 8 فـ 48 ÷ 6 = 8. الخارج 1248. نتحقّق: 6 × 1248 = 7488 ✓.', 4)
