INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80107885-377a-526e-a268-a11ccdaa3787', '0af74aa2-3495-5976-acd4-0a345eac83ca', 'في رحلةٍ 200 تلميذ، تتّسع كلّ حافلةٍ لـ 8 تلاميذ. كم حافلةً يلزم لنقلهم جميعًا؟', '[{"id":"a","text":"25"},{"id":"b","text":"26"},{"id":"c","text":"24"},{"id":"d","text":"20"}]'::jsonb, 'a', '200 ÷ 8 = 25 والباقي 0 لأنّ 8 × 25 = 200. القسمة تامّة، فيلزم بالضبط 25 حافلةً دون فائض.', 5)
