INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ff9c0a4-1f84-5ffc-ae99-3664040a95bf', '0af74aa2-3495-5976-acd4-0a345eac83ca', 'ما خارج وباقي القسمة 365 ÷ 5؟', '[{"id":"a","text":"الخارج 73 والباقي 0"},{"id":"b","text":"الخارج 71 والباقي 10"},{"id":"c","text":"الخارج 72 والباقي 5"},{"id":"d","text":"الخارج 63 والباقي 0"}]'::jsonb, 'a', 'منصوبًا: 3 ÷ 5 لا يمكن فنأخذ 36 ÷ 5 = 7 ب 1، ننزّل 5 فنحصل 15، و 15 ÷ 5 = 3 ب 0. الخارج 73 والباقي 0. نتحقّق: 5 × 73 = 365 ✓. الخطأ الشائع «الباقي 10» أو 5: كلاهما ليس أصغر من 5.', 6)
