INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e832f037-32ca-5699-9ed7-69d6ca2b4fcc', '633dcedf-f3f7-52f8-9fad-1df967367492', 'في قسمةٍ مقسومُها 23 وخارجُها 4 وباقيها 3، ما هو المقسوم عليه؟', '[{"id":"a","text":"5"},{"id":"b","text":"4"},{"id":"c","text":"6"},{"id":"d","text":"20"}]'::jsonb, 'a', 'بالعلاقة الأساسيّة المقسوم = (المقسوم عليه × الخارج) + الباقي. نجرّب 5: (5 × 4) + 3 = 23 ✓، والباقي 3 أصغر من 5 ✓. فالمقسوم عليه 5.', 2)
