INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9abc0aa0-981a-56eb-9d61-0e9e708a6200', '633dcedf-f3f7-52f8-9fad-1df967367492', 'نوزّع 43 حلوى على 6 أطفالٍ بالتساوي. كم حلوى لكلّ طفل، وكم يبقى؟', '[{"id":"a","text":"لكلٍّ 6 ويبقى 7"},{"id":"b","text":"لكلٍّ 8 ويبقى 0"},{"id":"c","text":"لكلٍّ 7 ويبقى 1"},{"id":"d","text":"لكلٍّ 7 ويبقى 6"}]'::jsonb, 'c', '43 ÷ 6 = 7 والباقي 1 لأنّ (6 × 7) + 1 = 43، والباقي 1 أصغر من 6 ✓. الخطأ الشائع «يبقى 7» أكبر من المقسوم عليه 6.', 4)
