  ('901c9876-d243-51db-a404-a4fe49dc2382', '633dcedf-f3f7-52f8-9fad-1df967367492', 'ما خارج وباقي القسمة 53 ÷ 7؟', '[{"id":"a","text":"الخارج 8 والباقي 3"},{"id":"b","text":"الخارج 7 والباقي 4"},{"id":"c","text":"الخارج 7 والباقي 6"},{"id":"d","text":"الخارج 6 والباقي 11"}]'::jsonb, 'b', '7 × 7 = 49 و 53 − 49 = 4، فالخارج 7 والباقي 4، والباقي أصغر من 7 ✓. الخطأ الشائع «الخارج 8»: 7 × 8 = 56 وهو أكبر من 53.', 6)
