INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('93a8ae4a-b848-507d-9cc7-aa6ec9cdd63d', '74912f65-e6ea-5e91-bd9e-6117f2f508cb', 'ما الكسر الذي يمثّله الجزء الملوّن في هذا القرص؟ <svg viewBox="0 0 100 100"><circle cx="50" cy="50" r="40" fill="none" stroke="currentColor" stroke-width="2.5"/><path d="M50 50 L90 50 A40 40 0 0 0 50 10 Z" fill="#d1d5db" stroke="currentColor" stroke-width="2"/><line x1="10" y1="50" x2="90" y2="50" stroke="currentColor" stroke-width="2"/><line x1="50" y1="10" x2="50" y2="90" stroke="currentColor" stroke-width="2"/></svg>', '[{"id":"a","text":"1/2"},{"id":"b","text":"1/4"},{"id":"c","text":"1/3"},{"id":"d","text":"4/1"}]'::jsonb, 'b', 'القرص مقسومٌ إلى 4 أجزاء متساوية، والملوّن جزءٌ واحد منها، فالكسر 1/4 (البسط 1 فوق والمقام 4 تحت).', 1)
