  ('a187bc93-343b-57ae-bd02-516d346a64f5', 'c854e3eb-b6a8-595f-b931-e588850cbb82', 'اختر الشكل الذي يمثّل الكسر 1/3 بالضبط.', '[{"id":"a","text":"<svg viewBox=\"0 0 100 50\"><rect x=\"8\" y=\"12\" width=\"84\" height=\"26\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/><rect x=\"8\" y=\"12\" width=\"28\" height=\"26\" fill=\"#d1d5db\" stroke=\"currentColor\" stroke-width=\"2\"/><line x1=\"36\" y1=\"12\" x2=\"36\" y2=\"38\" stroke=\"currentColor\" stroke-width=\"2\"/><line x1=\"64\" y1=\"12\" x2=\"64\" y2=\"38\" stroke=\"currentColor\" stroke-width=\"2\"/></svg>"},{"id":"b","text":"<svg viewBox=\"0 0 100 50\"><rect x=\"8\" y=\"12\" width=\"84\" height=\"26\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/><rect x=\"8\" y=\"12\" width=\"42\" height=\"26\" fill=\"#d1d5db\" stroke=\"currentColor\" stroke-width=\"2\"/><line x1=\"50\" y1=\"12\" x2=\"50\" y2=\"38\" stroke=\"currentColor\" stroke-width=\"2\"/></svg>"},{"id":"c","text":"<svg viewBox=\"0 0 100 50\"><rect x=\"8\" y=\"12\" width=\"84\" height=\"26\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/><rect x=\"8\" y=\"12\" width=\"21\" height=\"26\" fill=\"#d1d5db\" stroke=\"currentColor\" stroke-width=\"2\"/><line x1=\"29\" y1=\"12\" x2=\"29\" y2=\"38\" stroke=\"currentColor\" stroke-width=\"2\"/><line x1=\"50\" y1=\"12\" x2=\"50\" y2=\"38\" stroke=\"currentColor\" stroke-width=\"2\"/><line x1=\"71\" y1=\"12\" x2=\"71\" y2=\"38\" stroke=\"currentColor\" stroke-width=\"2\"/></svg>"},{"id":"d","text":"<svg viewBox=\"0 0 100 50\"><rect x=\"8\" y=\"12\" width=\"84\" height=\"26\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/><rect x=\"8\" y=\"12\" width=\"56\" height=\"26\" fill=\"#d1d5db\" stroke=\"currentColor\" stroke-width=\"2\"/><line x1=\"36\" y1=\"12\" x2=\"36\" y2=\"38\" stroke=\"currentColor\" stroke-width=\"2\"/><line x1=\"64\" y1=\"12\" x2=\"64\" y2=\"38\" stroke=\"currentColor\" stroke-width=\"2\"/></svg>"}]'::jsonb, 'a', 'الكسر 1/3 يعني جزءًا واحدًا ملوّنًا من 3 أجزاء متساوية، وهذا ما يظهره الشكل (a). الشكل (b) جزآن (1/2)، و(c) 4 أجزاء، و(d) جزآن ملوّنان من 3 (2/3).', 2)
