INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d3031d9-0459-5025-a785-cc56bcdcaad5', '11f8f01e-8800-5fc1-b252-a5ec467c6ee7', 'ما الكسر الذي يمثّله الجزء الملوّن؟ <svg viewBox="0 0 100 100"><circle cx="50" cy="50" r="40" fill="none" stroke="currentColor" stroke-width="2.5"/><path d="M50 50 L10 50 A40 40 0 0 0 50 90 Z" fill="#d1d5db" stroke="currentColor" stroke-width="2"/><line x1="10" y1="50" x2="90" y2="50" stroke="currentColor" stroke-width="2"/><line x1="50" y1="10" x2="50" y2="90" stroke="currentColor" stroke-width="2"/></svg>', '[{"id":"a","text":"3/4"},{"id":"b","text":"1/4"},{"id":"c","text":"1/2"},{"id":"d","text":"4/1"}]'::jsonb, 'b', 'القرص 4 أجزاء متساوية، والملوّن جزءٌ واحد، فالكسر 1/4.', 1)
