INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1dfd2a9c-9731-510e-9af5-ead690673978', '11f8f01e-8800-5fc1-b252-a5ec467c6ee7', 'كيف نكتب الكسر «خمسة أعشار» (خمسة أجزاء من عشرة)؟', '[{"id":"a","text":"10/5"},{"id":"b","text":"5/5"},{"id":"c","text":"1/5"},{"id":"d","text":"5/10"}]'::jsonb, 'd', 'البسط 5 (الأجزاء المأخوذة) فوق، والمقام 10 (الأجزاء كلّها) تحت، فالكسر 5/10.', 2)
