INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2565ef0e-a553-5213-8b72-709c7d11643a', '11f8f01e-8800-5fc1-b252-a5ec467c6ee7', 'ما هو 1/6 من 30 قطعة نقديّة؟', '[{"id":"a","text":"5"},{"id":"b","text":"6"},{"id":"c","text":"180"},{"id":"d","text":"24"}]'::jsonb, 'a', 'نقسم على المقام: 30 ÷ 6 = 5، ثمّ نضرب في البسط 1، فالجواب 5 قطع. تحقّق: 6 × 5 = 30 ✓.', 3)
