INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('14802917-beb8-5487-b6a0-d277ac7824a9', '11f8f01e-8800-5fc1-b252-a5ec467c6ee7', 'أيّ كسرٍ أكبر: 4/9 أم 7/9؟', '[{"id":"a","text":"4/9 لأنّ بسطه أصغر"},{"id":"b","text":"متساويان"},{"id":"c","text":"7/9 لأنّ بسطه أكبر والمقام واحد"},{"id":"d","text":"4/9 لأنّ المقام أكبر"}]'::jsonb, 'c', 'المقامان متساويان (9)، فالأجزاء من نفس الحجم ونقارن البسطين: 7 أكبر من 4، فإنّ 7/9 أكبر. الخطأ الشائع: الاعتقاد أنّ المقام يقرّر الأكبر.', 4)
