  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df89e6d8-0a6f-54f2-a5f7-c89dc79a2eb3', '11f8f01e-8800-5fc1-b252-a5ec467c6ee7', 'شريطٌ قُسم إلى 5 أجزاء متساوية، لُوّن منها 3. ما الكسر الملوّن وما الباقي؟', '[{"id":"a","text":"الملوّن 3/5 والباقي 2/5"},{"id":"b","text":"الملوّن 2/5 والباقي 3/5"},{"id":"c","text":"الملوّن 5/3 والباقي 5/2"},{"id":"d","text":"الملوّن 3/5 والباقي 3/5"}]'::jsonb, 'a', 'الملوّن 3 من 5 أي 3/5، والباقي 5 − 3 = 2 أي 2/5. الخطأ الشائع: قلب الكسر إلى 5/3 أو خلط الملوّن بالباقي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
