INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1c22d5b0-4768-5e13-9394-dd96c7a7022d', '11f8f01e-8800-5fc1-b252-a5ec467c6ee7', 'صحنٌ فيه 16 تمرة، أكل خالد 1/4 وأكلت أخته 1/2 من الصحن. كم تمرةً بقيت؟', '[{"id":"a","text":"8"},{"id":"b","text":"4"},{"id":"c","text":"12"},{"id":"d","text":"6"}]'::jsonb, 'b', 'خالد: 1/4 من 16 = 16 ÷ 4 = 4. أخته: 1/2 من 16 = 16 ÷ 2 = 8. أُكل 4 + 8 = 12، فالباقي 16 − 12 = 4 تمرات. الخطأ الشائع: نسيان جمع النصيبين قبل الطرح.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

