INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eea8826c-212a-5060-961d-e6458c316c8f', '4616b944-201a-5dad-be4b-803b56ad9951', 'كم خطوةً في أقصر مسلكٍ من العقدة (1 ; 1) إلى العقدة (1 ; 4)؟', '[{"id":"a","text":"خطوتان"},{"id":"b","text":"5 خطوات"},{"id":"c","text":"3 خطوات"},{"id":"d","text":"4 خطوات"}]'::jsonb, 'c', 'العقدتان على نفس السطر (1)، فلا نزول. فرق الأعمدة: 4 − 1 = 3، فالمسافة 3 خطوات أفقيًّا فقط.', 4)
