INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2f7ad40-c3f7-5bcc-970f-bc2f9f63499e', '4a2ae96c-00ef-5b51-93b4-10926c922eb6', 'في الشبكة، الخطّ الأفقيّ نسمّيه:', '[{"id":"a","text":"العمود"},{"id":"b","text":"السطر"},{"id":"c","text":"العقدة"},{"id":"d","text":"الخانة"}]'::jsonb, 'b', 'السطر خطٌّ أفقيّ، والعمود خطٌّ عموديّ. نُرقّم الأسطر من الأعلى إلى الأسفل والأعمدة من اليسار إلى اليمين.', 1)
