  ('0c96f3d8-65b9-5836-a155-e61a25c5cf06', '4a2ae96c-00ef-5b51-93b4-10926c922eb6', 'ما موضع العقدة السوداء؟ <svg viewBox="0 0 130 110"><line x1="20" y1="20" x2="110" y2="20" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="50" x2="110" y2="50" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="80" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="20" x2="20" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="50" y1="20" x2="50" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="80" y1="20" x2="80" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="110" y1="20" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><text x="8" y="24" font-size="9" fill="currentColor">1</text><text x="8" y="54" font-size="9" fill="currentColor">2</text><text x="8" y="84" font-size="9" fill="currentColor">3</text><text x="18" y="14" font-size="9" fill="currentColor">1</text><text x="48" y="14" font-size="9" fill="currentColor">2</text><text x="78" y="14" font-size="9" fill="currentColor">3</text><text x="108" y="14" font-size="9" fill="currentColor">4</text><circle cx="110" cy="80" r="4.5" fill="currentColor"/></svg>', '[{"id":"a","text":"(4 ; 3)"},{"id":"b","text":"(3 ; 3)"},{"id":"c","text":"(4 ; 4)"},{"id":"d","text":"(3 ; 4)"}]'::jsonb, 'd', 'العقدة في الزاوية: السطر 3 (الأسفل) والعمود 4 (أقصى اليمين). نكتب السطر أوّلًا ثمّ العمود، فموضعها (3 ; 4).', 3)
