INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('223644b7-9596-5032-bc96-73098966deef', '4a2ae96c-00ef-5b51-93b4-10926c922eb6', 'كم خطوةً في هذا المسلك؟ <svg viewBox="0 0 130 110"><line x1="20" y1="20" x2="110" y2="20" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="50" x2="110" y2="50" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="80" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="20" x2="20" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="50" y1="20" x2="50" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="80" y1="20" x2="80" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="110" y1="20" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><polyline points="20,50 20,80 50,80" fill="none" stroke="currentColor" stroke-width="3.5"/><circle cx="20" cy="50" r="4" fill="currentColor"/><circle cx="50" cy="80" r="4" fill="currentColor"/></svg>', '[{"id":"a","text":"3 خطوات"},{"id":"b","text":"خطوتان"},{"id":"c","text":"خطوة واحدة"},{"id":"d","text":"4 خطوات"}]'::jsonb, 'b', 'المسلك فيه 3 عقد لكن طولُه عدد القطع بينها: خطوة نزولًا ثمّ خطوة أفقيًّا، أي خطوتان. عدد الخطوات = عدد العقد ناقص 1.', 4)
