INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba7f455e-4cd2-51e3-ac7d-bed666ac48d1', 'd0bc0d12-c70a-5f9a-a8b8-2d0dbeb2e06f', 'ما طول أقصر مسلكٍ من العقدة (1 ; 1) إلى العقدة (3 ; 3)؟', '[{"id":"a","text":"3 خطوات"},{"id":"b","text":"4 خطوات"},{"id":"c","text":"6 خطوات"},{"id":"d","text":"5 خطوات"}]'::jsonb, 'b', 'المسافة = (فرق الأعمدة) + (فرق الأسطر). فرق الأعمدة: 3 − 1 = 2، وفرق الأسطر: 3 − 1 = 2، فالمجموع 2 + 2 = 4 خطوات.', 1)
