  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ad25964-d698-5823-a257-c146595430ff', 'd0bc0d12-c70a-5f9a-a8b8-2d0dbeb2e06f', 'العقدتان (2 ; 1) و(2 ; 5) على نفس السطر. ما طول أقصر مسلكٍ بينهما؟', '[{"id":"a","text":"6 خطوات"},{"id":"b","text":"5 خطوات"},{"id":"c","text":"3 خطوات"},{"id":"d","text":"4 خطوات"}]'::jsonb, 'd', 'العقدتان على نفس السطر فلا نزول. فرق الأعمدة: 5 − 1 = 4، فالمسافة 4 خطوات أفقيًّا فقط. الخطأ الشائع: عدّ العقد (5 عقد) بدل القطع؛ والصواب عدد القطع = 4.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de133261-6cbc-5a1a-9250-c177c00abebf', 'd0bc0d12-c70a-5f9a-a8b8-2d0dbeb2e06f', 'ماذا نسمّي مسلكين مختلفين في الشكل لكنّهما متساويان في عدد الخطوات؟', '[{"id":"a","text":"مسلكان متكافئان"},{"id":"b","text":"مسلكان مختصران فقط"},{"id":"c","text":"مسلكٌ واحد"},{"id":"d","text":"خانتان"}]'::jsonb, 'a', 'المسلكان المتكافئان مختلفان شكلًا ومتساويان طولًا (نفس عدد الخطوات). كلّ المسالك المختصرة بين عقدتين متكافئة لأنّ لها كلّها طول المسافة نفسه.', 3)
ON CONFLICT (id) DO UPDATE SET
