  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b134f80-5db4-5104-8d33-1e338e759aac', 'd0bc0d12-c70a-5f9a-a8b8-2d0dbeb2e06f', 'أيُّ المسلكين أقصر بين النقطتين السوداوين؟ <svg viewBox="0 0 130 110"><line x1="20" y1="20" x2="110" y2="20" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="50" x2="110" y2="50" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="80" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="20" x2="20" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="50" y1="20" x2="50" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="80" y1="20" x2="80" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="110" y1="20" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><polyline points="20,20 50,20 50,50" fill="none" stroke="#1f2937" stroke-width="3"/><polyline points="20,20 20,80 50,80 80,80 80,50 50,50" fill="none" stroke="#ef4444" stroke-width="3" stroke-dasharray="4 3"/><circle cx="20" cy="20" r="4" fill="currentColor"/><circle cx="50" cy="50" r="4" fill="currentColor"/></svg>', '[{"id":"a","text":"المسلك المنقّط (الأحمر)"},{"id":"b","text":"هما متساويان"},{"id":"c","text":"المسلك المتّصل (الأسود)"},{"id":"d","text":"لا يمكن المعرفة"}]'::jsonb, 'c', 'المسلك المتّصل لا يرجع للوراء: خطوة أفقيًّا ثمّ خطوة نزولًا = خطوتان (وهو المسافة). المسلك المنقّط يدور ويرجع، فطولُه أكبر. الخطأ الشائع: الظنّ أنّ كلّ المسالك متساوية؛ المتكافئة فقط هي المختصرة التي لا ترجع للوراء.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad99cf9c-0356-5df8-a91a-8524b92ff8ee', 'd0bc0d12-c70a-5f9a-a8b8-2d0dbeb2e06f', 'من العقدة (1 ; 2) نسير خطوتين إلى اليمين ثمّ خطوةً واحدة إلى الأسفل. عند أيّ عقدةٍ نصل؟', '[{"id":"a","text":"(2 ; 3)"},{"id":"b","text":"(2 ; 4)"},{"id":"c","text":"(3, 4)"},{"id":"d","text":"(2 ; 2)"}]'::jsonb, 'b', 'خطوتان إلى اليمين تزيدان العمود: 2 + 2 = 4. خطوة إلى الأسفل تزيد السطر: 1 + 1 = 2. نصل إلى (2 ; 4). الخطأ الشائع: خلط اليمين (عمود) بالأسفل (سطر).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6155ef7c-f3ca-5fbd-924d-d6ebb6130c5b', 'd0bc0d12-c70a-5f9a-a8b8-2d0dbeb2e06f', 'كم خطوةً في هذا المسلك الكامل؟ <svg viewBox="0 0 130 110"><line x1="20" y1="20" x2="110" y2="20" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="50" x2="110" y2="50" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="80" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="20" x2="20" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="50" y1="20" x2="50" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="80" y1="20" x2="80" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="110" y1="20" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><polyline points="20,20 50,20 50,50 80,50 80,80" fill="none" stroke="currentColor" stroke-width="3.5"/><circle cx="20" cy="20" r="4" fill="currentColor"/><circle cx="80" cy="80" r="4" fill="currentColor"/></svg>', '[{"id":"a","text":"3 خطوات"},{"id":"b","text":"6 خطوات"},{"id":"c","text":"5 خطوات"},{"id":"d","text":"4 خطوات"}]'::jsonb, 'd', 'نعدّ القطع على التوالي: يمين، أسفل، يمين، أسفل = 4 خطوات. المسلك يمرّ بـ 5 عقد، وعدد الخطوات = عدد العقد ناقص 1 = 4.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

