  ('82b3ca00-b346-5837-a332-5c89f96bb921', '46936662-d6d1-57cd-b9d2-f4a72c8121dd', 'math-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): الشبكة والمسالك', 2, 75, 15, 'practice', 'admin', 3)
