INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('130e9418-c727-5336-93bd-cced46475291', '82b3ca00-b346-5837-a332-5c89f96bb921', 'في الشبكة، المربّع الصغير المحصور بين أربع عقد نسمّيه:', '[{"id":"a","text":"العقدة"},{"id":"b","text":"السطر"},{"id":"c","text":"الخانة"},{"id":"d","text":"العمود"}]'::jsonb, 'c', 'الخانة هي المربّع الصغير المحصور بين أربع عقد. أمّا العقدة فهي نقطة تقاطعٍ، والسطر والعمود خطّان.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89f484de-7ad5-5140-9a81-d6d6d9482e63', '82b3ca00-b346-5837-a332-5c89f96bb921', 'ما موضع الكنز المعلّم بالنقطة السوداء؟ <svg viewBox="0 0 130 110"><line x1="20" y1="20" x2="110" y2="20" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="50" x2="110" y2="50" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="80" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="20" x2="20" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="50" y1="20" x2="50" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="80" y1="20" x2="80" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="110" y1="20" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><text x="8" y="24" font-size="9" fill="currentColor">1</text><text x="8" y="54" font-size="9" fill="currentColor">2</text><text x="8" y="84" font-size="9" fill="currentColor">3</text><text x="18" y="14" font-size="9" fill="currentColor">1</text><text x="48" y="14" font-size="9" fill="currentColor">2</text><text x="78" y="14" font-size="9" fill="currentColor">3</text><text x="108" y="14" font-size="9" fill="currentColor">4</text><circle cx="80" cy="80" r="4.5" fill="currentColor"/></svg>', '[{"id":"a","text":"(3 ; 3)"},{"id":"b","text":"(3 ; 4)"},{"id":"c","text":"(2 ; 3)"},{"id":"d","text":"(4 ; 3)"}]'::jsonb, 'a', 'النقطة على السطر 3 (الأسفل) والعمود 3. نكتب السطر أوّلًا ثمّ العمود، فموضع الكنز (3 ; 3).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6052b06e-e563-50ee-82ab-732b6d4b9b74', '82b3ca00-b346-5837-a332-5c89f96bb921', 'ينطلق المغامر من العقدة (1 ; 1) ويريد بلوغ العقدة (2 ; 4). ما طول أقصر مسلك؟', '[{"id":"a","text":"3 خطوات"},{"id":"b","text":"6 خطوات"},{"id":"c","text":"5 خطوات"},{"id":"d","text":"4 خطوات"}]'::jsonb, 'd', 'المسافة = (فرق الأعمدة) + (فرق الأسطر). فرق الأعمدة: 4 − 1 = 3، وفرق الأسطر: 2 − 1 = 1، فالمجموع 3 + 1 = 4 خطوات.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2816330-644b-577e-90f1-bd84470e5d3d', '82b3ca00-b346-5837-a332-5c89f96bb921', 'من العقدة (3 ; 2) نصعد خطوةً واحدة إلى الأعلى. عند أيّ عقدةٍ نصل؟', '[{"id":"a","text":"(3 ; 3)"},{"id":"b","text":"(2 ; 2)"},{"id":"c","text":"(3 ; 1)"},{"id":"d","text":"(4 ; 2)"}]'::jsonb, 'b', 'الصعود إلى الأعلى يُنقص رقم السطر بمقدار 1: 3 − 1 = 2، والعمود لا يتغيّر (2). نصل إلى (2 ; 2). الأسطر تُعَدّ من الأعلى، فالصعود يُنقص السطر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('044d783a-8ebe-5cd5-b5a5-923156395e04', '82b3ca00-b346-5837-a332-5c89f96bb921', 'للذهاب من (1 ; 2) إلى (3 ; 2) رسم سامي ثلاثة مسالك مختلفة، كلٌّ منها لا يرجع للوراء. ما طول كلّ مسلكٍ منها؟', '[{"id":"a","text":"تختلف الأطوال"},{"id":"b","text":"3 خطوات"},{"id":"c","text":"خطوتان"},{"id":"d","text":"4 خطوات"}]'::jsonb, 'c', 'العقدتان على نفس العمود (2)، وفرق الأسطر 3 − 1 = 2. كلّ مسلكٍ مختصرٍ طولُه المسافة نفسها: خطوتان. هذه مسالك متكافئة (مختلفة شكلًا، متساوية طولًا).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d694bc43-88c3-5687-8806-8a27ca9ad846', '82b3ca00-b346-5837-a332-5c89f96bb921', 'عقدتان موضعهما (2 ; 3) و(2 ; 3). ماذا نقول عنهما؟', '[{"id":"a","text":"هما العقدة نفسها (المسافة 0)"},{"id":"b","text":"بينهما خطوة واحدة"},{"id":"c","text":"بينهما خطوتان"},{"id":"d","text":"على عمودين مختلفين"}]'::jsonb, 'a', 'لهما نفس السطر ونفس العمود، فهما العقدة نفسها. فرق الأعمدة 0 وفرق الأسطر 0، فالمسافة 0 + 0 = 0 خطوة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

