  ('6cfec581-b85a-597c-9e3b-8a8bf16a5061', '46936662-d6d1-57cd-b9d2-f4a72c8121dd', 'math-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: ألغاز الشبكة والمسالك', 4, 300, 60, 'challenge', 'admin', 4)
