INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('035a272e-baf2-5fc1-b951-05d897c5f0cd', '6cfec581-b85a-597c-9e3b-8a8bf16a5061', 'كنزٌ في العقدة (4 ; 5) ومغامرٌ في العقدة (1, 1). ما طول أقصر مسلكٍ يبلغ به الكنز؟', '[{"id":"a","text":"9 خطوات"},{"id":"b","text":"7 خطوات"},{"id":"c","text":"5 خطوات"},{"id":"d","text":"8 خطوات"}]'::jsonb, 'b', 'المسافة = (فرق الأعمدة) + (فرق الأسطر). فرق الأعمدة: 5 − 1 = 4، وفرق الأسطر: 4 − 1 = 3، فالمجموع 4 + 3 = 7 خطوات.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46b09425-1618-5fd7-95cc-934df7726c99', '6cfec581-b85a-597c-9e3b-8a8bf16a5061', 'ننقل هذا المثلّث 3 خانات إلى اليمين. إلى أيّ موضعٍ ينتقل رأسُه الأعلى الذي موضعه (1 ; 1)؟ <svg viewBox="0 0 160 110"><line x1="15" y1="20" x2="150" y2="20" stroke="#9ca3af" stroke-width="1"/><line x1="15" y1="50" x2="150" y2="50" stroke="#9ca3af" stroke-width="1"/><line x1="15" y1="80" x2="150" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="15" y1="20" x2="15" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="45" y1="20" x2="45" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="75" y1="20" x2="75" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="105" y1="20" x2="105" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="135" y1="20" x2="135" y2="80" stroke="#9ca3af" stroke-width="1"/><polygon points="15,20 15,50 45,50" fill="none" stroke="currentColor" stroke-width="3"/></svg>', '[{"id":"a","text":"(4 ; 1)"},{"id":"b","text":"(1 ; 3)"},{"id":"c","text":"(1 ; 4)"},{"id":"d","text":"(3 ; 1)"}]'::jsonb, 'c', 'النقل إلى اليمين يزيد العمود فقط ويُبقي السطر. السطر يبقى 1، والعمود 1 + 3 = 4، فينتقل الرأس إلى (1 ; 4). الخطأ الشائع: تغيير السطر؛ النقل أفقيًّا لا يغيّر السطر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b156d3d5-4ebb-55b5-bddf-d98ad52261c0', '6cfec581-b85a-597c-9e3b-8a8bf16a5061', 'من (1 ; 1) إلى (2 ; 2)، كم عدد المسالك المختصرة المختلفة (المتكافئة) الممكنة؟', '[{"id":"a","text":"مسلكان"},{"id":"b","text":"مسلكٌ واحد"},{"id":"c","text":"4 مسالك"},{"id":"d","text":"3 مسالك"}]'::jsonb, 'a', 'نحتاج خطوةً يمينًا وخطوةً أسفل (المسافة 2). الترتيب إمّا «يمين ثمّ أسفل» أو «أسفل ثمّ يمين»، فهما مسلكان مختصران متكافئان فقط. الخطأ الشائع: عدّ مساراتٍ ترجع للوراء، وهي ليست مختصرة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f6c654b-ca38-54b8-88e2-933c082c6ca4', '6cfec581-b85a-597c-9e3b-8a8bf16a5061', 'ذهب فريد من (1 ; 1) إلى (1 ; 4) فقطع 5 خطوات، بينما تحتاج المسافة 3 خطوات فقط. ماذا نستنتج عن مسلكه؟', '[{"id":"a","text":"مسلكه مختصر"},{"id":"b","text":"المسافة خاطئة"},{"id":"c","text":"العقدتان على عمودٍ واحد"},{"id":"d","text":"مسلكه ليس مختصرًا (رجع للوراء)"}]'::jsonb, 'd', 'المسافة بين العقدتين 3 خطوات (نفس السطر، فرق الأعمدة 4 − 1 = 3). فريد قطع 5 > 3، فمسلكه غير مختصر: رجع للوراء أو دار. الخطأ الشائع: ظنّ أنّ أيّ مسلكٍ مختصر؛ المختصر فقط يساوي المسافة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6a63804-5f8d-5744-8c72-c5097d0a5ce9', '6cfec581-b85a-597c-9e3b-8a8bf16a5061', 'ينطلق المغامر من (2 ; 2)، يسير خطوةً يمينًا، ثمّ خطوتين أسفل، ثمّ خطوةً يسارًا. عند أيّ عقدةٍ يصل؟', '[{"id":"a","text":"(4 ; 3)"},{"id":"b","text":"(2 ; 2)"},{"id":"c","text":"(4 ; 2)"},{"id":"d","text":"(2 ; 4)"}]'::jsonb, 'c', 'العمود: 2 + 1 (يمين) − 1 (يسار) = 2. السطر: 2 + 2 (أسفل) = 4. نصل إلى (4 ; 2). الخطأ الشائع: جمع كلّ الخطوات في اتّجاهٍ واحد؛ اليمين واليسار يتعاكسان فيلغي أحدهما الآخر هنا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f1289af-eabb-5848-89fd-8bb639b395bc', '6cfec581-b85a-597c-9e3b-8a8bf16a5061', 'العقدتان (1 ; 5) و(3 ; 1). أيّ جملةٍ صحيحة عن أقصر مسلكٍ بينهما؟', '[{"id":"a","text":"طولُه 4 خطوات"},{"id":"b","text":"طولُه 6 خطوات: 4 أفقيًّا و2 عموديًّا"},{"id":"c","text":"طولُه خطوتان"},{"id":"d","text":"لا يوجد مسلكٌ بينهما"}]'::jsonb, 'b', 'فرق الأعمدة: 5 − 1 = 4 (أفقيًّا)، وفرق الأسطر: 3 − 1 = 2 (عموديًّا)، فالمسافة 4 + 2 = 6 خطوات. الخطأ الشائع: جمع الأرقام دون طرحٍ، أو خلط الأفقيّ بالعموديّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

