INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d861514-573a-5e80-95bc-16bc240dd006', '10c31f10-9dca-5145-9ab9-b1b1ea695c23', 'في زوج الموضع (سطر، عمود)، ماذا يمثّل الرقم الأوّل؟', '[{"id":"a","text":"العمود"},{"id":"b","text":"عدد الخطوات"},{"id":"c","text":"السطر"},{"id":"d","text":"عدد العقد"}]'::jsonb, 'c', 'الرقم الأوّل في الزوج هو السطر (كم نزلنا من الأعلى)، والرقم الثاني هو العمود (كم تقدّمنا من اليسار). الترتيب: السطر أوّلًا ثمّ العمود.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
