INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c70ac24c-c3b6-5a0c-8ce6-51db34cf648a', '10c31f10-9dca-5145-9ab9-b1b1ea695c23', 'ما موضع العقدة السوداء؟ <svg viewBox="0 0 130 110"><line x1="20" y1="20" x2="110" y2="20" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="50" x2="110" y2="50" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="80" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="20" x2="20" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="50" y1="20" x2="50" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="80" y1="20" x2="80" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="110" y1="20" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><text x="8" y="24" font-size="9" fill="currentColor">1</text><text x="8" y="54" font-size="9" fill="currentColor">2</text><text x="8" y="84" font-size="9" fill="currentColor">3</text><text x="18" y="14" font-size="9" fill="currentColor">1</text><text x="48" y="14" font-size="9" fill="currentColor">2</text><text x="78" y="14" font-size="9" fill="currentColor">3</text><text x="108" y="14" font-size="9" fill="currentColor">4</text><circle cx="50" cy="20" r="4.5" fill="currentColor"/></svg>', '[{"id":"a","text":"(2 ; 1)"},{"id":"b","text":"(1 ; 2)"},{"id":"c","text":"(2 ; 2)"},{"id":"d","text":"(1 ; 1)"}]'::jsonb, 'b', 'العقدة على السطر 1 (الأعلى) والعمود 2. نكتب السطر أوّلًا ثمّ العمود، فموضعها (1 ; 2). الزوج (2 ; 1) معكوسٌ وخاطئ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('28383eb7-1f47-52c4-bd5e-d7de37eed871', '10c31f10-9dca-5145-9ab9-b1b1ea695c23', 'كم خطوةً في هذا المسلك؟ <svg viewBox="0 0 130 110"><line x1="20" y1="20" x2="110" y2="20" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="50" x2="110" y2="50" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="80" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="20" y1="20" x2="20" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="50" y1="20" x2="50" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="80" y1="20" x2="80" y2="80" stroke="#9ca3af" stroke-width="1"/><line x1="110" y1="20" x2="110" y2="80" stroke="#9ca3af" stroke-width="1"/><polyline points="20,80 20,50 50,50 50,20 80,20" fill="none" stroke="currentColor" stroke-width="3.5"/><circle cx="20" cy="80" r="4" fill="currentColor"/><circle cx="80" cy="20" r="4" fill="currentColor"/></svg>', '[{"id":"a","text":"5 خطوات"},{"id":"b","text":"3 خطوات"},{"id":"c","text":"5 عقد"},{"id":"d","text":"4 خطوات"}]'::jsonb, 'd', 'نعدّ القطع: أعلى، يمين، أعلى، يمين = 4 خطوات. المسلك يمرّ بـ 5 عقد، وعدد الخطوات = عدد العقد ناقص 1 = 4.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e00db776-28d9-5334-9214-cc385ed01b73', '10c31f10-9dca-5145-9ab9-b1b1ea695c23', 'من العقدة (3 ; 4) نسير خطوةً يسارًا ثمّ خطوةً إلى الأعلى. عند أيّ عقدةٍ نصل؟', '[{"id":"a","text":"(2 ; 3)"},{"id":"b","text":"(4 ; 5)"},{"id":"c","text":"(2 ; 5)"},{"id":"d","text":"(4 ; 3)"}]'::jsonb, 'a', 'خطوة يسارًا تُنقص العمود: 4 − 1 = 3. خطوة إلى الأعلى تُنقص السطر: 3 − 1 = 2. نصل إلى (2 ; 3). الأسطر تُعَدّ من الأعلى، فالصعود يُنقص السطر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c93bb813-de6c-59bd-abcd-460baf4e3e99', '10c31f10-9dca-5145-9ab9-b1b1ea695c23', 'ما طول أقصر مسلكٍ من العقدة (2 ; 1) إلى العقدة (4 ; 4)؟', '[{"id":"a","text":"4 خطوات"},{"id":"b","text":"7 خطوات"},{"id":"c","text":"5 خطوات"},{"id":"d","text":"6 خطوات"}]'::jsonb, 'c', 'المسافة = (فرق الأعمدة) + (فرق الأسطر). فرق الأعمدة: 4 − 1 = 3، وفرق الأسطر: 4 − 2 = 2، فالمجموع 3 + 2 = 5 خطوات.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2234fb85-fd6a-5b58-97e5-2a06600397e8', '10c31f10-9dca-5145-9ab9-b1b1ea695c23', 'مسلكان بين (1 ; 1) و(3 ; 2): الأوّل طولُه 3 خطوات لا يرجع للوراء، والثاني طولُه 5 خطوات. أيّ جملةٍ صحيحة؟', '[{"id":"a","text":"هما متكافئان"},{"id":"b","text":"الأوّل مختصر وهو المسافة، والثاني غير مختصر"},{"id":"c","text":"الثاني هو الأقصر"},{"id":"d","text":"المسافة بينهما 5 خطوات"}]'::jsonb, 'b', 'المسافة = فرق الأعمدة (2 − 1 = 1) + فرق الأسطر (3 − 1 = 2) = 3 خطوات. الأوّل (3) يساوي المسافة فهو مختصر، والثاني (5 > 3) يرجع للوراء فليس مختصرًا. ليسا متكافئين لاختلاف طولهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

