INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2733837b-4271-54c0-bdab-c00d32ee993b', '4dfbb773-0905-5766-9faa-aa37ca98b181', 'ما اسم الأداة التي نستعملها للتحقّق من أنّ مستقيمين متعامدان (يكوّنان زاوية قائمة)؟', '[{"id":"a","text":"الكوس"},{"id":"b","text":"الفرجار"},{"id":"c","text":"المنقلة"},{"id":"d","text":"القلم"}]'::jsonb, 'a', 'الكوس أداةٌ على شكل مثلّثٍ فيه زاوية قائمة، نطابق ركنه القائم مع المستقيمين للتحقّق من التعامد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('baca3b36-8827-560d-b152-3df5ba73c339', '4dfbb773-0905-5766-9faa-aa37ca98b181', 'مستقيمان لا يتقاطعان مهما امتدّا في الجهتين. ماذا نسمّيهما؟', '[{"id":"a","text":"متقاطعان"},{"id":"b","text":"متوازيان"},{"id":"c","text":"متعامدان"},{"id":"d","text":"في استقامة"}]'::jsonb, 'b', 'المستقيمان المتوازيان (∥) لا يتقاطعان أبدًا، والمسافة بينهما تبقى ثابتة مثل خطّي سكّة القطار.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2170262d-f9d0-51f3-8f24-ce219fb9e62e', '4dfbb773-0905-5766-9faa-aa37ca98b181', 'ما الرمز الذي يدلّ على التعامد بين مستقيمين؟', '[{"id":"a","text":"∥"},{"id":"b","text":"="},{"id":"c","text":"⊥"},{"id":"d","text":"+"}]'::jsonb, 'c', 'الرمز ⊥ يدلّ على التعامد (زاوية قائمة)، أمّا الرمز ∥ فيدلّ على التوازي.', 3)
ON CONFLICT (id) DO UPDATE SET
