  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a629742-be63-5b9b-ac8f-c3c4167da3de', '4dfbb773-0905-5766-9faa-aa37ca98b181', 'انظر إلى الشكل. المربّع الصغير عند نقطة التقاطع يدلّ على أنّ المستقيمين: <svg viewBox="0 0 120 90"><line x1="15" y1="60" x2="105" y2="60" stroke="currentColor" stroke-width="2.5"/><line x1="60" y1="15" x2="60" y2="85" stroke="currentColor" stroke-width="2.5"/><rect x="60" y="48" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2"/></svg>', '[{"id":"a","text":"متوازيان"},{"id":"b","text":"لا يتقاطعان"},{"id":"c","text":"في استقامة"},{"id":"d","text":"متعامدان"}]'::jsonb, 'd', 'المربّع الصغير عند التقاطع يدلّ على زاوية قائمة، فالمستقيمان متعامدان (⊥).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('103a6363-3381-5d7b-849a-a6449b7a767b', '4dfbb773-0905-5766-9faa-aa37ca98b181', 'النقاط A وB وC في استقامة. ما معنى ذلك؟', '[{"id":"a","text":"يمرّ بها مستقيمٌ واحد"},{"id":"b","text":"تكوّن زاوية قائمة"},{"id":"c","text":"لا يمرّ بها أيّ مستقيم"},{"id":"d","text":"كلّ نقطتين متعامدتان"}]'::jsonb, 'a', 'نقاطٌ في استقامة معناها أنّ مستقيمًا واحدًا يمرّ بها جميعًا، ونتحقّق بوضع المسطرة عليها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
