INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdd40778-df65-5d0e-8f02-1aaffe8696de', 'f6a36f1b-b0cf-50cd-9c88-6d68b509af50', 'ما اسم جزء المستقيم المحصور بين نقطتين A وB، له بدايةٌ ونهاية؟', '[{"id":"a","text":"النقطة"},{"id":"b","text":"نصف المستقيم"},{"id":"c","text":"المستقيم اللانهائي"},{"id":"d","text":"القطعة المستقيمة [AB]"}]'::jsonb, 'd', 'القطعة المستقيمة [AB] هي الجزء المحصور بين النقطتين A وB، لها بدايةٌ ونهاية، بخلاف المستقيم الذي يمتدّ بلا نهاية.', 1)
