INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55595bc4-41c0-50cf-a8ab-db54bac6ef6c', 'f6a36f1b-b0cf-50cd-9c88-6d68b509af50', 'انظر إلى الشكل. ماذا نسمّي هذين المستقيمين؟ <svg viewBox="0 0 120 70"><line x1="10" y1="25" x2="110" y2="25" stroke="currentColor" stroke-width="2.5"/><line x1="10" y1="50" x2="110" y2="50" stroke="currentColor" stroke-width="2.5"/></svg>', '[{"id":"a","text":"متعامدان"},{"id":"b","text":"متقاطعان"},{"id":"c","text":"متوازيان"},{"id":"d","text":"في استقامة"}]'::jsonb, 'c', 'المستقيمان في الشكل لا يتقاطعان والمسافة بينهما ثابتة، فهما متوازيان (∥).', 3)
