INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('896e816b-cb29-51f1-bbf5-61ae6d03db05', 'f6a36f1b-b0cf-50cd-9c88-6d68b509af50', 'مستقيمان متعامدان يكوّنان عند تقاطعهما زاوية:', '[{"id":"a","text":"قائمة"},{"id":"b","text":"مستقيمة"},{"id":"c","text":"صغيرة جدًّا"},{"id":"d","text":"لا زاوية بينهما"}]'::jsonb, 'a', 'التعامد (⊥) معناه أنّ المستقيمين يتقاطعان ويكوّنان زاوية قائمة، مثل ركن المربّع.', 5)
