INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6101c76-ad81-56a9-ab8b-2950d209e603', 'f6a36f1b-b0cf-50cd-9c88-6d68b509af50', 'للتحقّق من أنّ ثلاث نقاط في استقامة، نضع حافّة:', '[{"id":"a","text":"الكوس على إحدى النقاط"},{"id":"b","text":"الفرجار بين النقطتين"},{"id":"c","text":"المنقلة فوق النقاط"},{"id":"d","text":"المسطرة على النقطتين الطرفيتين"}]'::jsonb, 'd', 'نضع حافّة المسطرة على النقطتين الطرفيتين؛ إن لمست النقطة الوسطى الحافّة فالنقاط الثلاث في استقامة.', 6)
