INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('913ba6ec-7895-5e1a-9d06-e4c09cb3388c', 'f0220e55-caeb-50c8-a2ae-12f6fab08d0d', 'انظر إلى الشكل. ما العلاقة بين المستقيمين؟ <svg viewBox="0 0 120 90"><line x1="15" y1="20" x2="105" y2="75" stroke="currentColor" stroke-width="2.5"/><line x1="15" y1="75" x2="105" y2="20" stroke="currentColor" stroke-width="2.5"/><circle cx="60" cy="47.5" r="3.5" fill="currentColor"/></svg>', '[{"id":"a","text":"متوازيان"},{"id":"b","text":"متقاطعان (دون مربّع زاوية قائمة)"},{"id":"c","text":"متعامدان"},{"id":"d","text":"لا يلتقيان"}]'::jsonb, 'b', 'المستقيمان يلتقيان في نقطة، لكن لا يوجد مربّعٌ صغير يدلّ على زاوية قائمة، فهما متقاطعان فقط وليسا متعامدين. الخطأ الشائع: ظنّ كلّ متقاطعين متعامدين؛ التعامد يحتاج زاوية قائمة (⊥).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
