INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24014ed5-2818-51fb-a7b1-f7c4dece1a79', 'f0220e55-caeb-50c8-a2ae-12f6fab08d0d', 'أيّ جملةٍ صحيحةٌ عن المستقيمين المتوازيين؟', '[{"id":"a","text":"يتقاطعان في نقطةٍ بعيدة"},{"id":"b","text":"يكوّنان زاوية قائمة"},{"id":"c","text":"لا يتقاطعان مهما امتدّا"},{"id":"d","text":"يلتقيان في نقطتين"}]'::jsonb, 'c', 'المتوازيان لا يتقاطعان أبدًا مهما امتدّا، والمسافة بينهما ثابتة. الخطأ الشائع: ظنّ أنّهما يلتقيان «بعيدًا»؛ بل لا يلتقيان أبدًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
