  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('201233d0-5376-5fa5-be70-0546f565a87c', 'f0220e55-caeb-50c8-a2ae-12f6fab08d0d', 'نريد رسم مستقيمٍ عموديّ (متعامد) على مستقيمٍ معطى يمرّ بنقطة. ما الأداة المناسبة؟', '[{"id":"a","text":"الكوس"},{"id":"b","text":"الفرجار"},{"id":"c","text":"المنقلة فقط"},{"id":"d","text":"الممحاة"}]'::jsonb, 'a', 'نستعمل الكوس لأنّ فيه زاوية قائمة: نطابق أحد ضلعَي الزاوية القائمة مع المستقيم، ونرسم على طول الضلع الآخر فيكون المستقيم عموديًّا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dd944923-abd0-5735-97d5-8701b2b5a2b5', 'f0220e55-caeb-50c8-a2ae-12f6fab08d0d', 'إذا كان d1 ⊥ d2، فهذا يعني أنّ المستقيمين:', '[{"id":"a","text":"لا يتقاطعان"},{"id":"b","text":"يتقاطعان ويكوّنان زاوية قائمة"},{"id":"c","text":"متوازيان"},{"id":"d","text":"في استقامة واحدة"}]'::jsonb, 'b', 'الرمز ⊥ يدلّ على التعامد: المستقيمان يتقاطعان ويكوّنان زاوية قائمة. الخطأ الشائع: الخلط بين ⊥ (تعامد، يتقاطعان) و∥ (توازي، لا يتقاطعان).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('11f42e73-d999-580e-8409-a1a839ac2473', 'f0220e55-caeb-50c8-a2ae-12f6fab08d0d', 'أيّ مقارنةٍ بين التعامد والتوازي صحيحة؟', '[{"id":"a","text":"المتعامدان يتقاطعان، والمتوازيان لا يتقاطعان"},{"id":"b","text":"كلاهما لا يتقاطع"},{"id":"c","text":"كلاهما يتقاطع بزاوية قائمة"},{"id":"d","text":"المتوازيان يتقاطعان والمتعامدان لا"}]'::jsonb, 'a', 'المتعامدان (⊥) يتقاطعان بزاوية قائمة، أمّا المتوازيان (∥) فلا يتقاطعان أبدًا. الخطأ الشائع: عكس الرمزين أو الظنّ أنّ كليهما يتقاطع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f7d361a-7613-5803-86cb-94351a6185d3', 'f0220e55-caeb-50c8-a2ae-12f6fab08d0d', 'مستقيمٌ d3 عموديٌّ على d1، ومستقيمٌ d1 نفسه. كم زاوية قائمة تتكوّن عند تقاطع d3 مع d1 (الزوايا الأربع متساوية)؟', '[{"id":"a","text":"زاوية قائمة واحدة فقط"},{"id":"b","text":"زاويتان"},{"id":"c","text":"4 زوايا قائمة"},{"id":"d","text":"لا زاوية قائمة"}]'::jsonb, 'c', 'عند تعامد مستقيمين تتكوّن 4 زوايا حول نقطة التقاطع، وكلّها قائمة ومتساوية، فعددها 4. نكتفي برسم مربّعٍ واحد للدلالة عليها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

