  ('b839e8c3-34fa-5578-a1ff-0fcda10a92c9', '888ef9f1-194a-5fa0-9c8a-0e1717e0ce17', 'math-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): الاستقامة والتعامد والتوازي', 2, 75, 15, 'practice', 'admin', 3)
