INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bef620dd-db2c-5d8c-b8da-ce15fb7d1554', 'b839e8c3-34fa-5578-a1ff-0fcda10a92c9', 'خطٌّ يبدأ من نقطةٍ ويمتدّ في جهةٍ واحدة فقط بلا نهاية. ما اسمه؟', '[{"id":"a","text":"القطعة المستقيمة"},{"id":"b","text":"النقطة"},{"id":"c","text":"المستقيم الكامل"},{"id":"d","text":"نصف المستقيم"}]'::jsonb, 'd', 'نصف المستقيم يبدأ من نقطةٍ واحدة ويمتدّ في جهةٍ واحدة بلا نهاية، بخلاف القطعة المحصورة بين نقطتين.', 1)
ON CONFLICT (id) DO UPDATE SET
