  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('870c725b-eb86-5322-8b63-53558d726fe0', 'b839e8c3-34fa-5578-a1ff-0fcda10a92c9', 'انظر إلى الشكل. هل النقاط A وB وC في استقامة؟ <svg viewBox="0 0 130 60"><line x1="15" y1="20" x2="115" y2="45" stroke="currentColor" stroke-width="2"/><circle cx="25" cy="22.5" r="3" fill="currentColor"/><circle cx="65" cy="32.5" r="3" fill="currentColor"/><circle cx="105" cy="42.5" r="3" fill="currentColor"/><text x="20" y="16" font-size="10" fill="currentColor">A</text><text x="60" y="45" font-size="10" fill="currentColor">B</text><text x="100" y="36" font-size="10" fill="currentColor">C</text></svg>', '[{"id":"a","text":"نعم، يمرّ بها مستقيمٌ واحد"},{"id":"b","text":"لا، كلّ واحدة في جهة"},{"id":"c","text":"نعم، لأنّها متعامدة"},{"id":"d","text":"لا، لأنّها متوازية"}]'::jsonb, 'a', 'في الشكل يمرّ مستقيمٌ واحد بالنقاط A وB وC جميعًا، فهي في استقامة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a309166-0c93-5848-8bf6-d1de379e7c1c', 'b839e8c3-34fa-5578-a1ff-0fcda10a92c9', 'ما الرمز الذي يدلّ على التوازي بين مستقيمين؟', '[{"id":"a","text":"⊥"},{"id":"b","text":"∥"},{"id":"c","text":"×"},{"id":"d","text":"="}]'::jsonb, 'b', 'الرمز ∥ يدلّ على التوازي (لا يتقاطعان)، أمّا ⊥ فيدلّ على التعامد (زاوية قائمة).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b79b2893-602c-5640-b730-9a4e7704354b', 'b839e8c3-34fa-5578-a1ff-0fcda10a92c9', 'أيّ علامةٍ نرسمها عند نقطة التقاطع لنبيّن أنّ المستقيمين متعامدان؟', '[{"id":"a","text":"دائرة صغيرة"},{"id":"b","text":"سهم"},{"id":"c","text":"مربّع صغير"},{"id":"d","text":"نجمة"}]'::jsonb, 'c', 'نرسم مربّعًا صغيرًا عند نقطة التقاطع للدلالة على الزاوية القائمة، أي على التعامد (⊥).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de92a34a-3554-51c7-8476-d0e7488bda12', 'b839e8c3-34fa-5578-a1ff-0fcda10a92c9', 'خطّا سكّة القطار يبقيان على بُعدٍ ثابتٍ ولا يلتقيان. هذه صورةٌ لمستقيمين:', '[{"id":"a","text":"متوازيين"},{"id":"b","text":"متعامدين"},{"id":"c","text":"متقاطعين"},{"id":"d","text":"في استقامة"}]'::jsonb, 'a', 'خطّا السكّة لا يلتقيان والمسافة بينهما ثابتة، فهما متوازيان (∥).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
