  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('923b62ff-abd3-5050-abd2-3203af77812c', 'b839e8c3-34fa-5578-a1ff-0fcda10a92c9', 'أيّ جملةٍ خاطئة؟', '[{"id":"a","text":"المستقيم يمتدّ في الجهتين بلا نهاية"},{"id":"b","text":"القطعة المستقيمة لها بدايةٌ ونهاية"},{"id":"c","text":"المتوازيان يتقاطعان في نقطة"},{"id":"d","text":"المتعامدان يكوّنان زاوية قائمة"}]'::jsonb, 'c', 'الجملة الخاطئة هي «المتوازيان يتقاطعان»: المتوازيان لا يتقاطعان أبدًا. باقي الجمل صحيحة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
