INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('17dc78d1-74f0-5fc8-8cab-5731a7ad675b', '8f23bbee-442b-5312-9094-63c333a6ec61', 'أنا علاقةٌ بين مستقيمين: يتقاطعان ويكوّنان أربع زوايا قائمة. ما رمزي؟', '[{"id":"a","text":"∥"},{"id":"b","text":"⊥"},{"id":"c","text":"="},{"id":"d","text":"+"}]'::jsonb, 'b', 'التقاطع بزاوية قائمة هو التعامد، ورمزه ⊥. الخطأ الشائع: اختيار ∥ وهو رمز التوازي حيث لا يتقاطع المستقيمان أبدًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63f12ea1-b797-5c0b-9f7c-25ec00e0a7e1', '8f23bbee-442b-5312-9094-63c333a6ec61', 'انظر إلى الشكل. ما العلاقة الصحيحة بين المستقيمين؟ <svg viewBox="0 0 120 90"><line x1="15" y1="60" x2="105" y2="60" stroke="currentColor" stroke-width="2.5"/><line x1="60" y1="15" x2="60" y2="85" stroke="currentColor" stroke-width="2.5"/><rect x="60" y="48" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2"/></svg>', '[{"id":"a","text":"d1 ∥ d2"},{"id":"b","text":"لا يتقاطعان"},{"id":"c","text":"في استقامة"},{"id":"d","text":"d1 ⊥ d2"}]'::jsonb, 'd', 'المربّع الصغير عند التقاطع يدلّ على زاوية قائمة، فالمستقيمان متعامدان: d1 ⊥ d2. الخطأ الشائع: كتابة ∥ مع وجود مربّع الزاوية القائمة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('98a8796a-aed8-5371-be46-a3896c4a03d3', '8f23bbee-442b-5312-9094-63c333a6ec61', 'مستقيمٌ d1 عموديٌّ على d2، وd2 عموديٌّ على d3 (والثلاثة في المستوى نفسه). ما العلاقة بين d1 وd3؟', '[{"id":"a","text":"متوازيان (d1 ∥ d3)"},{"id":"b","text":"متعامدان (d1 ⊥ d3)"},{"id":"c","text":"في استقامة"},{"id":"d","text":"يتقاطعان بزاوية قائمة"}]'::jsonb, 'a', 'إذا تعامد مستقيمان على مستقيمٍ ثالثٍ نفسه، كانا متوازيين، فـ d1 ∥ d3. الخطأ الشائع: ظنّ أنّ d1 ⊥ d3؛ لكنّ العموديّين على مستقيمٍ واحد يكونان متوازيين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ab003a3-2a49-5fd1-8308-5057f3f7d23a', '8f23bbee-442b-5312-9094-63c333a6ec61', 'عند مريم مستقيمان لا يلتقيان، وعند أحمد مستقيمان يلتقيان بزاوية قائمة. ما العلاقتان على الترتيب؟', '[{"id":"a","text":"مريم: متعامدان — أحمد: متوازيان"},{"id":"b","text":"كلاهما متوازيان"},{"id":"c","text":"مريم: متوازيان — أحمد: متعامدان"},{"id":"d","text":"كلاهما متعامدان"}]'::jsonb, 'c', 'ما لا يلتقي = متوازيان (مريم، ∥)، وما يلتقي بزاوية قائمة = متعامدان (أحمد، ⊥). الخطأ الشائع: عكس العلاقتين أو الخلط بين الرمزين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d42fa268-e852-551f-b751-d4be92e9aa67', '8f23bbee-442b-5312-9094-63c333a6ec61', 'أيّ جملةٍ صحيحةٌ دائمًا؟', '[{"id":"a","text":"المتعامدان حالةٌ خاصّة من المتقاطعين (يتقاطعان بزاوية قائمة)"},{"id":"b","text":"كلّ مستقيمين يتقاطعان حتمًا"},{"id":"c","text":"المتوازيان يتقاطعان في نقطة واحدة"},{"id":"d","text":"كلّ متقاطعين متعامدان"}]'::jsonb, 'a', 'المتعامدان يتقاطعان بزاوية قائمة، فهما حالةٌ خاصّة من المتقاطعين. الخطأ الشائع: «كلّ متقاطعين متعامدان» خطأ، لأنّ التقاطع قد يكون بزاوية غير قائمة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('25af2b5a-b931-54b4-8eba-66b80b25df50', '8f23bbee-442b-5312-9094-63c333a6ec61', 'ثلاث نقاط في استقامة، ونقطةٌ رابعة خارج هذا المستقيم. كم مستقيمًا واحدًا يمرّ بالنقاط الثلاث الأولى مجتمعةً؟', '[{"id":"a","text":"مستقيمان"},{"id":"b","text":"3 مستقيمات"},{"id":"c","text":"لا يمرّ بها مستقيم"},{"id":"d","text":"مستقيمٌ واحد"}]'::jsonb, 'd', 'كون النقاط الثلاث في استقامة يعني أنّ مستقيمًا واحدًا يمرّ بها جميعًا. النقطة الرابعة خارجه لا تغيّر ذلك. الخطأ الشائع: عدّ مستقيماتٍ متعدّدة؛ بل واحدٌ فقط يمرّ بالنقاط المستقيمة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

