  ('6e36b953-e472-5284-bbaf-91d2ff0e1207', '888ef9f1-194a-5fa0-9c8a-0e1717e0ce17', 'math-4eme', '📝 تدريب ⭐⭐⭐: إتقان الاستقامة والتعامد والتوازي (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
