INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('764e9122-2f7a-53b3-adcd-a35d7dd4f037', '6e36b953-e472-5284-bbaf-91d2ff0e1207', 'النقطة نسمّيها عادةً بـ:', '[{"id":"a","text":"حرفٍ كبير مثل A"},{"id":"b","text":"رقمٍ مثل 7"},{"id":"c","text":"رمزٍ مثل ⊥"},{"id":"d","text":"كلمةٍ كاملة"}]'::jsonb, 'a', 'نسمّي النقطة بحرفٍ كبير مثل A وB وC لتمييزها بسهولة في الرسم.', 1)
