INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e762dac-8cdd-5b64-9797-94d569aa5c40', '6e36b953-e472-5284-bbaf-91d2ff0e1207', 'انظر إلى الشكل. ما الأداة المرسومة، وما الزاوية المميَّزة فيها بالمربّع الصغير؟ <svg viewBox="0 0 120 90"><path d="M20 75 L100 75 L20 20 Z" fill="#d1d5db" stroke="currentColor" stroke-width="2.5"/><rect x="20" y="63" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2"/></svg>', '[{"id":"a","text":"المسطرة — لا زاوية"},{"id":"b","text":"الكوس — زاوية قائمة"},{"id":"c","text":"الفرجار — دائرة"},{"id":"d","text":"المنقلة — زاوية مفتوحة"}]'::jsonb, 'b', 'الشكل مثلّثٌ فيه مربّعٌ صغير عند أحد الأركان، فهو الكوس وزاويته المميَّزة قائمة، ونستعمله للتعامد.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0807bf6d-1d54-5bc6-9541-1f325ee4eb01', '6e36b953-e472-5284-bbaf-91d2ff0e1207', 'للتحقّق من أنّ مستقيمين متوازيان، نتأكّد من أنّهما:', '[{"id":"a","text":"يلتقيان في نقطة"},{"id":"b","text":"يكوّنان زاوية قائمة"},{"id":"c","text":"في استقامة واحدة"},{"id":"d","text":"لا يلتقيان والمسافة بينهما ثابتة"}]'::jsonb, 'd', 'المتوازيان لا يلتقيان مهما امتدّا، والمسافة بينهما ثابتة. نتحقّق بإسناد الكوس على المسطرة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
