INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ded2980-d253-53b5-9001-8a9c934879be', '6e36b953-e472-5284-bbaf-91d2ff0e1207', 'أيّ ترتيبٍ يصف الانتقال من الأصغر إلى الأكبر امتدادًا؟', '[{"id":"a","text":"القطعة المستقيمة، ثمّ نصف المستقيم، ثمّ المستقيم"},{"id":"b","text":"المستقيم، ثمّ القطعة، ثمّ نصف المستقيم"},{"id":"c","text":"نصف المستقيم، ثمّ المستقيم، ثمّ القطعة"},{"id":"d","text":"المستقيم، ثمّ نصف المستقيم، ثمّ القطعة"}]'::jsonb, 'a', 'القطعة محصورة بين نقطتين (الأقصر)، ونصف المستقيم يمتدّ في جهةٍ واحدة، والمستقيم يمتدّ في الجهتين بلا نهاية (الأطول).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a634697b-715e-57c5-a73e-4dd27ad9468c', '6e36b953-e472-5284-bbaf-91d2ff0e1207', 'مستقيمان متوازيان d1 وd2، ومستقيمٌ ثالث d3 عموديٌّ على d1. ما علاقة d3 بـ d2؟', '[{"id":"a","text":"موازٍ لـ d2"},{"id":"b","text":"في استقامة مع d2"},{"id":"c","text":"لا علاقة بينهما"},{"id":"d","text":"عموديٌّ على d2 أيضًا"}]'::jsonb, 'd', 'إذا عامد مستقيمٌ أحد المتوازيين عامد الآخر أيضًا، فـ d3 ⊥ d2. الخطأ الشائع: ظنّ d3 موازيًا لـ d2؛ لكنّه عموديٌّ عليهما معًا.', 5)
ON CONFLICT (id) DO UPDATE SET
