INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc424702-ce2f-56c4-af54-3f063eb2aa94', '6e36b953-e472-5284-bbaf-91d2ff0e1207', 'أيّ جملةٍ تجمع الفرق بدقّة؟', '[{"id":"a","text":"⊥ تعني لا يتقاطعان، و∥ تعني يتقاطعان بزاوية قائمة"},{"id":"b","text":"⊥ و∥ يدلّان على الشيء نفسه"},{"id":"c","text":"⊥ تعني يتقاطعان بزاوية قائمة، و∥ تعني لا يتقاطعان أبدًا"},{"id":"d","text":"كلاهما يعني نقاطًا في استقامة"}]'::jsonb, 'c', '⊥ (تعامد): يتقاطعان بزاوية قائمة؛ ∥ (توازي): لا يتقاطعان أبدًا. الخطأ الشائع: عكس معنى الرمزين.', 6)
