INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('931aaf53-cd1a-5820-9977-61f03b16ee33', 'd94592d6-1145-5021-8d89-0c8c102e3393', 'طبّقنا الكوس على زاوية فخرج أحد ضلعيها خارج الكوس. ما نوع الزاوية؟', '[{"id":"a","text":"حادّة"},{"id":"b","text":"منفرجة"},{"id":"c","text":"قائمة"},{"id":"d","text":"مستقيمة"}]'::jsonb, 'b', 'خروج الضلع خارج الكوس يعني أنّ الفتحة أكبر من القائمة، فالزاوية منفرجة. لو بقي الضلع داخل الكوس لكانت حادّة.', 2)
