INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83955216-6350-5798-94b1-d9ae3b28256c', 'd94592d6-1145-5021-8d89-0c8c102e3393', 'ما نوع هذه الزاوية؟ <svg viewBox="0 0 100 100"><line x1="50" y1="82" x2="95" y2="82" stroke="currentColor" stroke-width="2.5"/><line x1="50" y1="82" x2="14.8" y2="52.4" stroke="currentColor" stroke-width="2.5"/><circle cx="50" cy="82" r="2.8" fill="currentColor"/></svg>', '[{"id":"a","text":"قائمة"},{"id":"b","text":"حادّة"},{"id":"c","text":"منفرجة"},{"id":"d","text":"مستقيمة"}]'::jsonb, 'c', 'الفتحة أوسع من زاوية الركن القائم وأصغر من نصف الدورة، فالزاوية منفرجة. ليست قائمة لأنّه لا يوجد ركنٌ تامّ.', 3)
