INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a75b4996-4db3-5a6f-b414-353004898364', 'd94592d6-1145-5021-8d89-0c8c102e3393', 'زاويتان لهما الفتحة نفسها، لكنّ ضلعَي الأولى أطول من ضلعَي الثانية. أيّهما أكبر؟', '[{"id":"a","text":"الأولى (ذات الضلعين الأطول)"},{"id":"b","text":"الثانية"},{"id":"c","text":"هما متساويتان"},{"id":"d","text":"لا يمكن المقارنة"}]'::jsonb, 'c', 'الزاوية لا تتعلّق بطول الضلعين بل بالفتحة وحدها. الخطأ الشائع أن نظنّ الضلع الأطول يكبّر الزاوية؛ ما دامت الفتحة نفسها فالزاويتان متساويتان.', 4)
