INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc352272-eab6-541b-9e5a-eeff5109f9ae', 'd94592d6-1145-5021-8d89-0c8c102e3393', 'زاوية قيسها 180°. ما نوعها، وكيف يبدو ضلعاها؟', '[{"id":"a","text":"قائمة، وضلعاها متعامدان"},{"id":"b","text":"مستقيمة، وضلعاها على استقامةٍ واحدة"},{"id":"c","text":"حادّة، وفتحتها ضيّقة"},{"id":"d","text":"منفرجة، وفتحتها واسعة قليلًا"}]'::jsonb, 'b', 'قيس 180° هو الزاوية المستقيمة، ضلعاها على استقامةٍ واحدة فيبدوان كخطّ. الخطأ الشائع خلطها بالقائمة؛ القائمة 90° (نصفها) وضلعاها متعامدان لا مستقيمان.', 5)
