INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f517e4fc-0306-5599-916a-5090ca235a36', 'c1c49516-0f61-5a5a-9761-37923d87cdb1', 'الزاوية المستقيمة ضعف الزاوية القائمة. فإذا كانت القائمة 90°، فكم قيس المستقيمة؟', '[{"id":"a","text":"90°"},{"id":"b","text":"أصغر من القائمة"},{"id":"c","text":"مثل القائمة تمامًا"},{"id":"d","text":"180°"}]'::jsonb, 'd', 'ضعف القائمة هو 90° + 90° = 180°، وهو قيس الزاوية المستقيمة (نصف دورة).', 6)
