INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6343b757-275d-5449-9989-ce5ab3d9646e', '84bfc0d6-4e19-5587-94a0-4b5f48d65928', 'أنا زاوية ضلعاي على استقامةٍ واحدة فأبدو كأنّي خطّ مستقيم. من أكون؟', '[{"id":"a","text":"قائمة"},{"id":"b","text":"حادّة"},{"id":"c","text":"منفرجة"},{"id":"d","text":"مستقيمة"}]'::jsonb, 'd', 'الزاوية التي ضلعاها على استقامةٍ واحدة هي المستقيمة، قيسها 180°. الخطأ الشائع خلطها بالقائمة، لكنّ القائمة 90° وضلعاها متعامدان لا مستقيمان.', 1)
