INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a396a8f-bb59-5b20-8e7c-e0ea0aedee3a', '84bfc0d6-4e19-5587-94a0-4b5f48d65928', 'كم زاوية قائمة نجمع لنحصل على زاوية مستقيمة؟', '[{"id":"a","text":"زاوية واحدة"},{"id":"b","text":"زاويتان"},{"id":"c","text":"ثلاث زوايا"},{"id":"d","text":"أربع زوايا"}]'::jsonb, 'b', 'القائمة 90° والمستقيمة 180°، و90° + 90° = 180°، فنحتاج زاويتين قائمتين. الخطأ الشائع اختيار أربع زوايا، لكنّ أربع قوائم تساوي دورةً كاملة لا نصفها.', 4)
