INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9b6f224-2502-5e6b-b18c-1283c104fdb8', '2f455886-684b-5038-a215-39afbe7f9ac3', 'زاويتان فتحتاهما متساويتان وضلعاهما مختلفان في الطول. كيف نقارنهما؟', '[{"id":"a","text":"الأكبر هي ذات الضلعين الأطول"},{"id":"b","text":"الأكبر هي ذات الضلعين الأقصر"},{"id":"c","text":"لا يمكن مقارنتهما أبدًا"},{"id":"d","text":"هما متساويتان لأنّ الفتحة واحدة"}]'::jsonb, 'd', 'الزاوية تُقاس بالفتحة لا بطول الضلعين، فما دامت الفتحة واحدة فالزاويتان متساويتان. الخطأ الشائع ربط كِبَر الزاوية بطول الضلعين.', 4)
