INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31e29c28-d20b-5501-85d4-24022c775cec', '2f455886-684b-5038-a215-39afbe7f9ac3', 'أيّ ترتيبٍ صحيحٌ للزوايا من الأكبر إلى الأصغر؟', '[{"id":"a","text":"مستقيمة، منفرجة، قائمة، حادّة"},{"id":"b","text":"حادّة، قائمة، منفرجة، مستقيمة"},{"id":"c","text":"قائمة، مستقيمة، حادّة، منفرجة"},{"id":"d","text":"منفرجة، مستقيمة، حادّة، قائمة"}]'::jsonb, 'a', 'من الأكبر إلى الأصغر: مستقيمة (180°) ثمّ منفرجة (أكبر من القائمة) ثمّ قائمة (90°) ثمّ حادّة (أصغر من القائمة). الخطأ الشائع البدء بالحادّة، وهي الأصغر لا الأكبر.', 5)
