INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce53beda-b3a3-53a3-b179-b56790c79672', '2f455886-684b-5038-a215-39afbe7f9ac3', 'في المستطيل، طبّقنا الكوس على كلّ ركن من أركانه الأربعة فانطبق تمامًا. ما نوع زواياه؟', '[{"id":"a","text":"كلّها حادّة"},{"id":"b","text":"كلّها منفرجة"},{"id":"c","text":"بعضها قائمة وبعضها حادّة"},{"id":"d","text":"كلّها قائمة"}]'::jsonb, 'd', 'انطباق الكوس تمامًا على كلّ ركن يعني أنّ كلّ الزوايا قائمة (90°)، وهذا حال المستطيل والمربّع: زواياهما الأربع قائمة.', 6)
