INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d87916a4-8c90-5c64-af50-9db57ce3f49b', 'ac869942-70e5-5c8d-8b98-4a482d7db3f4', 'ما هذا الشكل؟ <svg viewBox="0 0 120 100"><rect x="16" y="34" width="88" height="42" fill="none" stroke="currentColor" stroke-width="2.5"/><rect x="16" y="67" width="9" height="9" fill="none" stroke="#ef4444" stroke-width="1.3"/><line x1="56" y1="32" x2="64" y2="32" stroke="#ef4444" stroke-width="1.5"/><line x1="12" y1="50" x2="12" y2="58" stroke="#ef4444" stroke-width="1.5"/><line x1="15" y1="50" x2="15" y2="58" stroke="#ef4444" stroke-width="1.5"/></svg>', '[{"id":"a","text":"المربّع"},{"id":"b","text":"المستطيل"},{"id":"c","text":"المثلّث"},{"id":"d","text":"السداسيّ"}]'::jsonb, 'b', 'الطول أكبر من العرض، والشرطة الواحدة على الطولين تختلف عن الشرطتين على العرضين، فالأضلاع المتقابلة فقط متساوية: إنّه المستطيل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae1b4494-c34d-5096-a333-559a6cdc8bd8', 'ac869942-70e5-5c8d-8b98-4a482d7db3f4', 'الخطأ الشائع: قال تلميذٌ إنّ كلّ شكلٍ له 4 أضلاع هو مربّع. أين الخطأ؟', '[{"id":"a","text":"المستطيل أيضًا له 4 أضلاع وليس مربّعًا؛ المربّع يلزمه تساوي كلّ الأضلاع"},{"id":"b","text":"لا خطأ، كلّ رباعيٍّ مربّع"},{"id":"c","text":"المربّع له 5 أضلاع"},{"id":"d","text":"الرباعيّ ليس مضلّعًا"}]'::jsonb, 'a', 'وجود 4 أضلاع يجعله رباعيًّا فقط. المستطيل وشبه المنحرف رباعيّاتٌ وليست مربّعات. المربّع يلزمه 4 أضلاع متساوية و4 زوايا قائمة معًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fa31b1d1-9d38-5378-b416-2070b444a118', 'ac869942-70e5-5c8d-8b98-4a482d7db3f4', 'كم رأسًا أكثر للسداسيّ من المثلّث؟', '[{"id":"a","text":"رأسان"},{"id":"b","text":"رأسٌ واحد"},{"id":"c","text":"3 رؤوس"},{"id":"d","text":"4 رؤوس"}]'::jsonb, 'c', 'للسداسيّ 6 رؤوس وللمثلّث 3 رؤوس، والفرق 6 − 3 = 3 رؤوس.', 5)
ON CONFLICT (id) DO UPDATE SET
