  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('43e0d96a-762c-5073-b87b-dcd13ca428d9', 'ac869942-70e5-5c8d-8b98-4a482d7db3f4', 'مثلّثٌ ليس فيه زاوية قائمة، وأضلاعه الثلاثة مختلفة الأطوال. ما نوعه؟', '[{"id":"a","text":"متساوي الأضلاع"},{"id":"b","text":"متساوي الساقين"},{"id":"c","text":"قائم الزاوية"},{"id":"d","text":"كيفيّ"}]'::jsonb, 'd', 'المثلّث الذي أضلاعه الثلاثة مختلفة ولا زاوية قائمة فيه هو المثلّث الكيفيّ (العاديّ).', 6)
