INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef2aaa92-52c6-5c6c-afdb-c1d3cc43445b', '7d3bbb81-359d-5c22-8158-f9a5e8bcdced', 'في كلّ مضلّعٍ، عدد الرؤوس:', '[{"id":"a","text":"يساوي عدد الأضلاع"},{"id":"b","text":"أكبر من عدد الأضلاع بواحد"},{"id":"c","text":"أصغر من عدد الأضلاع بواحد"},{"id":"d","text":"دائمًا 4"}]'::jsonb, 'a', 'في كلّ مضلّعٍ عدد الرؤوس يساوي عدد الأضلاع: المثلّث 3 و3، الرباعيّ 4 و4، وهكذا.', 1)
