INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9132197a-773c-5d43-ae35-cf0f4929a7bb', '7d3bbb81-359d-5c22-8158-f9a5e8bcdced', 'ما نوع هذا المثلّث؟ <svg viewBox="0 0 100 100"><polygon points="24,76 50,30 76,76" fill="none" stroke="currentColor" stroke-width="2.5"/><line x1="33" y1="54" x2="40" y2="50" stroke="#ef4444" stroke-width="1.6"/><line x1="60" y1="50" x2="67" y2="54" stroke="#ef4444" stroke-width="1.6"/><line x1="47" y1="77" x2="53" y2="77" stroke="#ef4444" stroke-width="1.6"/></svg>', '[{"id":"a","text":"قائم الزاوية"},{"id":"b","text":"كيفيّ"},{"id":"c","text":"متساوي الأضلاع"},{"id":"d","text":"ليس مثلّثًا"}]'::jsonb, 'c', 'الشرطة نفسها على الأضلاع الثلاثة تدلّ على أنّها متساوية، فهذا مثلّثٌ متساوي الأضلاع.', 2)
