INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80901c27-87a1-516e-bb70-20837f5b052c', '7d3bbb81-359d-5c22-8158-f9a5e8bcdced', 'أيّ جملةٍ صحيحةٌ عن المربّع؟', '[{"id":"a","text":"أضلاعه الأربعة متساوية وزواياه الأربعة قائمة"},{"id":"b","text":"له 3 أضلاع متساوية"},{"id":"c","text":"أضلاعه المتقابلة فقط متساوية"},{"id":"d","text":"خطّه منحنٍ"}]'::jsonb, 'a', 'المربّع رباعيٌّ أضلاعه الأربعة متساوية وزواياه الأربعة قائمة، وهذا ما يميّزه عن المستطيل العامّ.', 3)
