INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a9cdef1-3d95-5b06-9132-5a20f43bc05c', '7d3bbb81-359d-5c22-8158-f9a5e8bcdced', 'شكلٌ له 4 زوايا قائمة وطولُه يختلف عن عرضه. ما هو؟', '[{"id":"a","text":"المربّع"},{"id":"b","text":"المثلّث"},{"id":"c","text":"المستطيل"},{"id":"d","text":"الدائرة"}]'::jsonb, 'c', 'الزوايا الأربعة قائمة واختلاف الطول عن العرض يدلّان على المستطيل؛ لو تساوى الطول والعرض لصار مربّعًا.', 4)
