INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84fc6e17-7e09-542f-9e50-9ce0c2a9de4c', '7d3bbb81-359d-5c22-8158-f9a5e8bcdced', 'أيّ هذه المضلّعات له أكبر عددٍ من الأضلاع؟', '[{"id":"a","text":"المثلّث"},{"id":"b","text":"الرباعيّ"},{"id":"c","text":"الخماسيّ"},{"id":"d","text":"السداسيّ"}]'::jsonb, 'd', 'عدد الأضلاع: المثلّث 3، الرباعيّ 4، الخماسيّ 5، السداسيّ 6. فالسداسيّ صاحب أكبر عددٍ من الأضلاع.', 5)
