INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9081986-a49d-5adb-9105-3e3fb3b89b36', '7d3bbb81-359d-5c22-8158-f9a5e8bcdced', 'أكملْ: «المربّع هو حالةٌ خاصّة من …، لأنّ كلّ أضلاعه صارت متساوية.»', '[{"id":"a","text":"المثلّث"},{"id":"b","text":"المستطيل"},{"id":"c","text":"الدائرة"},{"id":"d","text":"الخماسيّ"}]'::jsonb, 'b', 'المربّع مستطيلٌ تساوت كلّ أضلاعه، فهو حالةٌ خاصّة من المستطيل: كلّ مربّعٍ مستطيل، وليس كلّ مستطيلٍ مربّعًا.', 6)
