INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34d1a4ad-d2a7-5746-bd07-81d985adef29', '35ff415f-3c98-59d8-a052-96f9e132f099', 'أنا مضلّعٌ لي 3 أضلاع، وفيَّ زاويةٌ قائمة واحدة. من أكون؟', '[{"id":"a","text":"مثلّثٌ قائم الزاوية"},{"id":"b","text":"المربّع"},{"id":"c","text":"مثلّثٌ متساوي الأضلاع"},{"id":"d","text":"المستطيل"}]'::jsonb, 'a', 'ثلاثة أضلاعٍ تجعله مثلّثًا، ووجود زاويةٍ قائمة يجعله مثلّثًا قائم الزاوية. المربّع والمستطيل لهما 4 أضلاع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a0f5d2ed-c9c3-5837-80e2-3b20df0bec6f', '35ff415f-3c98-59d8-a052-96f9e132f099', 'أنا رباعيٌّ زواياي الأربعة قائمة، وكلّ أضلاعي متساوية. من أكون؟', '[{"id":"a","text":"المستطيل العامّ"},{"id":"b","text":"المربّع"},{"id":"c","text":"المثلّث الكيفيّ"},{"id":"d","text":"الخماسيّ"}]'::jsonb, 'b', 'أربع زوايا قائمة مع تساوي كلّ الأضلاع تعني المربّع. المستطيل العامّ زواياه قائمة لكنّ طوله يختلف عن عرضه.', 2)
ON CONFLICT (id) DO UPDATE SET
