  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c784308-64bc-5cfb-86b1-ac8946ac9178', '35ff415f-3c98-59d8-a052-96f9e132f099', 'الخطأ الشائع: قال تلميذٌ إنّ المثلّث المتساوي الأضلاع لا يمكن أن يكون متساوي الساقين. أين الخطأ؟', '[{"id":"a","text":"متساوي الأضلاع أضلاعه الثلاثة متساوية، فهو أيضًا متساوي الساقين (وزيادة)"},{"id":"b","text":"لا خطأ، هما نوعان لا يجتمعان أبدًا"},{"id":"c","text":"المتساوي الأضلاع له 4 أضلاع"},{"id":"d","text":"المتساوي الساقين له زاوية قائمة دائمًا"}]'::jsonb, 'a', 'متساوي الساقين يكفيه ضلعان متساويان. المتساوي الأضلاع أضلاعه الثلاثة متساوية، فلديه ضلعان متساويان وزيادة، أي إنّه متساوي الساقين أيضًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34a2d609-9b8e-597b-948a-2623c4a74fae', '35ff415f-3c98-59d8-a052-96f9e132f099', 'إذا جمعنا عدد أضلاع المثلّث مع عدد أضلاع الخماسيّ، كم نحصل؟', '[{"id":"a","text":"7"},{"id":"b","text":"9"},{"id":"c","text":"8"},{"id":"d","text":"6"}]'::jsonb, 'c', 'للمثلّث 3 أضلاع وللخماسيّ 5 أضلاع، و3 + 5 = 8.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2013f7ea-9d68-511e-b7cd-e59d35e0b718', '35ff415f-3c98-59d8-a052-96f9e132f099', 'عند سعيدٍ شكلٌ زواياه الأربعة قائمة وطوله 7 ووحدةُ عرضه 7 أيضًا (الطول = العرض). ما هو بدقّة؟', '[{"id":"a","text":"مستطيلٌ فقط وليس مربّعًا"},{"id":"b","text":"مثلّث"},{"id":"c","text":"مربّع (لأنّ كلّ أضلاعه صارت متساوية)"},{"id":"d","text":"شكلٌ بلا اسم"}]'::jsonb, 'c', 'لمّا تساوى الطول والعرض صارت الأضلاع الأربعة متساوية مع بقاء الزوايا قائمة، فالشكل مربّع. المربّع حالةٌ خاصّة من المستطيل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a19269f3-b3a0-5c52-9029-a2d2973230f2', '35ff415f-3c98-59d8-a052-96f9e132f099', 'مضلّعٌ عدد أضلاعه يساوي عدد رؤوسه (طبعًا)، وهذا العدد بين 4 و6 ولا يساويهما. كم ضلعًا له؟', '[{"id":"a","text":"3"},{"id":"b","text":"6"},{"id":"c","text":"4"},{"id":"d","text":"5"}]'::jsonb, 'd', 'العدد بين 4 و6 ولا يساوي أيًّا منهما هو 5، فهو مضلّعٌ خماسيٌّ له 5 أضلاع و5 رؤوس.', 6)
