  ('eee6ed90-4566-5712-a7e8-a655ac56b207', '7260db0c-eee2-5e10-aec9-140c808a7f03', 'ما هذا المضلّع (عُدّ أضلاعه)? <svg viewBox="0 0 100 100"><polygon points="50,18 82,42 70,80 30,80 18,42" fill="none" stroke="currentColor" stroke-width="2.5"/></svg>', '[{"id":"a","text":"رباعيّ"},{"id":"b","text":"خماسيّ"},{"id":"c","text":"سداسيّ"},{"id":"d","text":"مثلّث"}]'::jsonb, 'b', 'للشكل 5 أضلاع و5 رؤوس، فهو مضلّعٌ خماسيّ.', 1)
