INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f22f5348-6b1c-5f64-aa0d-0636e7082eda', '0ace5fd9-c0cc-527b-99ee-167596204a62', 'مضلّعٌ خماسيّ منتظم (كلّ أضلاعه متساوية) طول ضلعه 8 cm. ما محيطه؟', '[{"id":"a","text":"13 cm"},{"id":"b","text":"16 cm"},{"id":"c","text":"32 cm"},{"id":"d","text":"40 cm"}]'::jsonb, 'd', 'للمضلّع الخماسيّ 5 أضلاع متساوية، فمحيطه = الضلع × 5 = 8 × 5 = 40 cm. الخطأ الشائع: الضرب في 4 (32) كأنّه مربّع، بدل الضرب في عدد أضلاعه 5.', 5)
