INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6491bc5c-be33-55a5-a944-a076782f4f14', '0ace5fd9-c0cc-527b-99ee-167596204a62', 'حديقةٌ على شكل مربّعٍ ضلعها 9 m، نريد إحاطتها بسياج. كم مترًا من السياج نحتاج؟', '[{"id":"a","text":"18 m"},{"id":"b","text":"36 m"},{"id":"c","text":"45 m"},{"id":"d","text":"81 m"}]'::jsonb, 'b', 'طول السياج = محيط المربّع = الضلع × 4 = 9 × 4 = 36 m. الخطأ الشائع: حساب 9 × 9 = 81 (هذه عمليّة المساحة لا المحيط).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
