INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88ae89dc-876e-50ba-8edc-3fdb648c2d97', 'dbbc6d6d-9744-5564-9d51-ad9d41021ee2', 'أيّ عمليّةٍ نستعملها لحساب محيط مربّعٍ معلوم الضلع؟', '[{"id":"a","text":"نقسم الضلع على 4"},{"id":"b","text":"نضرب الضلع في 4"},{"id":"c","text":"نضيف 4 إلى الضلع"},{"id":"d","text":"نضرب الضلع في الضلع"}]'::jsonb, 'b', 'أضلاع المربّع الأربعة متساوية، فمحيطه = الضلع × 4. نضرب لأنّ الضلع يتكرّر أربع مرّات، لا نجمع 4 ولا نقسم.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
