INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('841f0190-d57d-5f3f-92d5-8ee3eca37f78', 'dbbc6d6d-9744-5564-9d51-ad9d41021ee2', 'ما محيط مستطيلٍ طوله 15 cm وعرضه 10 cm؟', '[{"id":"a","text":"25 cm"},{"id":"b","text":"35 cm"},{"id":"c","text":"50 cm"},{"id":"d","text":"150 cm"}]'::jsonb, 'c', 'محيط المستطيل = (الطول + العرض) × 2 = (15 + 10) × 2 = 25 × 2 = 50 cm. لا نتوقّف عند 25 ولا نضرب الطول في العرض.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
