  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a1e129f-1977-5711-a272-79aca653f6f4', 'dbbc6d6d-9744-5564-9d51-ad9d41021ee2', 'ما محيط هذا المثلّث؟ <svg viewBox="0 0 100 100"><polygon points="50,16 88,84 12,84" fill="none" stroke="currentColor" stroke-width="2.5"/><text x="18" y="48" font-size="10" fill="currentColor">9 cm</text><text x="66" y="48" font-size="10" fill="currentColor">7 cm</text><text x="42" y="97" font-size="10" fill="currentColor">8 cm</text></svg>', '[{"id":"a","text":"16 cm"},{"id":"b","text":"24 cm"},{"id":"c","text":"25 cm"},{"id":"d","text":"30 cm"}]'::jsonb, 'b', 'محيط المثلّث = مجموع أضلاعه الثلاثة = 9 + 7 + 8 = 24 cm.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
