INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19ceb4c4-feb5-5483-a06a-0879ed543019', 'dbbc6d6d-9744-5564-9d51-ad9d41021ee2', 'مربّعٌ محيطه 32 cm. ما طول ضلعه؟', '[{"id":"a","text":"8 cm"},{"id":"b","text":"16 cm"},{"id":"c","text":"28 cm"},{"id":"d","text":"128 cm"}]'::jsonb, 'a', 'الضلع = المحيط ÷ 4 = 32 ÷ 4 = 8 cm. تحقّق: 8 × 4 = 32 cm ✓.', 4)
