INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08716741-7434-53c5-b0d4-ef5ceee5397f', 'dbbc6d6d-9744-5564-9d51-ad9d41021ee2', 'أردنا قياس محيط ملعب كرة القدم. ما الوحدة المناسبة؟', '[{"id":"a","text":"المليمتر (mm)"},{"id":"b","text":"السنتمتر (cm)"},{"id":"c","text":"المتر (m)"},{"id":"d","text":"الكيلوغرام (kg)"}]'::jsonb, 'c', 'الملعب كبير، فالمتر (m) هو الوحدة المناسبة. أمّا mm و cm فللأشياء الصغيرة، و kg وحدة كتلةٍ لا طول.', 5)
ON CONFLICT (id) DO UPDATE SET
