  ('4130fa83-396a-5635-979d-671db6c44f98', '66ceec91-d204-5426-9463-3c143954b077', 'math-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّد المحيط', 4, 300, 60, 'challenge', 'admin', 4)
