INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a9fce46-6b0c-510f-afe4-5567a3e5d5e9', '4130fa83-396a-5635-979d-671db6c44f98', 'مستطيلٌ محيطه 30 cm وطوله 9 cm. ما عرضه؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"12 cm"},{"id":"c","text":"15 cm"},{"id":"d","text":"21 cm"}]'::jsonb, 'a', 'نصف المحيط = الطول + العرض = 30 ÷ 2 = 15. إذن العرض = 15 − 9 = 6 cm. تحقّق: (9 + 6) × 2 = 30 cm ✓. الخطأ الشائع: طرح الطول من المحيط كاملًا (30 − 9 = 21) دون قسمته على 2 أوّلًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1dd80623-492d-519a-ad3c-fc4c0e88832a', '4130fa83-396a-5635-979d-671db6c44f98', 'مربّعٌ ومستطيلٌ لهما نفس المحيط. ضلع المربّع 10 cm، وطول المستطيل 13 cm. ما عرض المستطيل؟', '[{"id":"a","text":"3 cm"},{"id":"b","text":"7 cm"},{"id":"c","text":"10 cm"},{"id":"d","text":"27 cm"}]'::jsonb, 'b', 'محيط المربّع = 10 × 4 = 40 cm، وهو نفسه محيط المستطيل. نصف المحيط = 40 ÷ 2 = 20 = الطول + العرض. إذن العرض = 20 − 13 = 7 cm. تحقّق: (13 + 7) × 2 = 40 cm ✓. الخطأ الشائع: طرح الطول من المحيط كاملًا (40 − 13 = 27) دون أخذ نصف المحيط.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb623504-5da1-5ff4-beb9-ea9d4d11526a', '4130fa83-396a-5635-979d-671db6c44f98', 'ما محيط هذا الشكل المكوّن من مربّعٍ كبيرٍ نُقص منه مربّعٌ صغيرٌ من إحدى زواياه؟ <svg viewBox="0 0 100 100"><polygon points="15,15 75,15 75,55 55,55 55,85 15,85" fill="none" stroke="currentColor" stroke-width="2.5"/><text x="34" y="11" font-size="8" fill="currentColor">6 cm</text><text x="78" y="38" font-size="8" fill="currentColor">4 cm</text><text x="58" y="73" font-size="8" fill="currentColor">3 cm</text><text x="24" y="95" font-size="8" fill="currentColor">4 cm</text><text x="2" y="54" font-size="8" fill="currentColor">7 cm</text><text x="60" y="52" font-size="8" fill="currentColor">2 cm</text></svg>', '[{"id":"a","text":"20 cm"},{"id":"b","text":"22 cm"},{"id":"c","text":"26 cm"},{"id":"d","text":"30 cm"}]'::jsonb, 'c', 'نجمع أطوال أضلاع الخطّ المحيط كلّها مهما كان شكله: 6 + 4 + 3 + 2 + 4 + 7 = 26 cm. الخطأ الشائع: عدّ بعض الأضلاع فقط أو نسيان ضلعٍ من الزاوية المقطوعة، فينقص المجموع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('869e1d8c-5088-5677-b7aa-ea954ac10cca', '4130fa83-396a-5635-979d-671db6c44f98', 'صنع نجّارٌ إطارًا مستطيلًا طوله 40 cm وعرضه 25 cm، فبقي معه شريطٌ زخرفيّ طوله 150 cm بعد إحاطة الإطار. ما طول الشريط الذي كان معه في البداية؟', '[{"id":"a","text":"65 cm"},{"id":"b","text":"130 cm"},{"id":"c","text":"215 cm"},{"id":"d","text":"280 cm"}]'::jsonb, 'd', 'المستعمَل = محيط الإطار = (40 + 25) × 2 = 65 × 2 = 130 cm. الطول الأصليّ = المستعمَل + الباقي = 130 + 150 = 280 cm. الخطأ الشائع: نسيان إضافة الباقي (130 cm)، أو حساب 40 + 25 = 65 دون الضرب في 2.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('304ce8d6-3206-520b-8f13-183da52b7dac', '4130fa83-396a-5635-979d-671db6c44f98', 'حقلٌ مستطيلٌ طوله 60 m وعرضه 40 m. مشى فلّاحٌ حول الحقل دورتين كاملتين. كم مترًا قطع؟', '[{"id":"a","text":"100 m"},{"id":"b","text":"200 m"},{"id":"c","text":"400 m"},{"id":"d","text":"2400 m"}]'::jsonb, 'c', 'محيط الحقل = (60 + 40) × 2 = 100 × 2 = 200 m للدورة الواحدة. ولدورتين: 200 × 2 = 400 m. الخطأ الشائع: حساب محيط دورةٍ واحدة فقط (200 m) ونسيان ضربه في عدد الدورات.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a943b731-a4ec-5286-a975-7466aa8b5770', '4130fa83-396a-5635-979d-671db6c44f98', 'مثلّثٌ متساوي الأضلاع (أضلاعه الثلاثة متساوية) محيطه 21 cm. ما طول كلّ ضلعٍ منه؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"7 cm"},{"id":"c","text":"10 cm"},{"id":"d","text":"18 cm"}]'::jsonb, 'b', 'المثلّث متساوي الأضلاع له 3 أضلاع متساوية، فكلّ ضلع = المحيط ÷ 3 = 21 ÷ 3 = 7 cm. تحقّق: 7 + 7 + 7 = 21 cm ✓. الخطأ الشائع: القسمة على 2 (نحصل على 10 تقريبًا) بدل القسمة على عدد الأضلاع 3.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

