INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d3af044b-436d-564e-8318-4c2de909e375', '1ddcb865-d65d-5656-a69d-a2dfce1b8585', 'أيّ جملةٍ تصف المحيط وصفًا صحيحًا؟', '[{"id":"a","text":"هو عدد أضلاع الشكل"},{"id":"b","text":"هو طول أكبر ضلعٍ في الشكل"},{"id":"c","text":"هو السطح الذي يملؤه الشكل من الداخل"},{"id":"d","text":"هو طول الخطّ المحيط بالشكل = مجموع أطوال أضلاعه"}]'::jsonb, 'd', 'المحيط هو طول الخطّ المغلق المحيط بالشكل، أي مجموع أطوال أضلاعه كلّها، وليس عددها ولا أكبرها.', 1)
