INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d335152-1ee6-5932-a566-3c3bb51d9096', '1ddcb865-d65d-5656-a69d-a2dfce1b8585', 'مضلّعٌ سداسيّ منتظم (6 أضلاع متساوية) محيطه 30 cm. ما طول ضلعه؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"24 cm"},{"id":"d","text":"180 cm"}]'::jsonb, 'a', 'للمضلّع السداسيّ 6 أضلاع متساوية، فالضلع = المحيط ÷ 6 = 30 ÷ 6 = 5 cm. تحقّق: 5 × 6 = 30 cm ✓. الخطأ الشائع: القسمة على 4 (نحصل تقريبًا على غير ذلك) بدل القسمة على عدد الأضلاع 6.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24d18101-3b8c-5760-a8a2-215c9105d7e2', '1ddcb865-d65d-5656-a69d-a2dfce1b8585', 'غرفةٌ مستطيلة طولها 5 m وعرضها 4 m، نريد وضع شريطٍ زخرفيّ حول حوافّها كلّها. كم مترًا من الشريط نحتاج؟', '[{"id":"a","text":"9 m"},{"id":"b","text":"14 m"},{"id":"c","text":"18 m"},{"id":"d","text":"20 m"}]'::jsonb, 'c', 'طول الشريط = محيط الغرفة = (الطول + العرض) × 2 = (5 + 4) × 2 = 9 × 2 = 18 m. الخطأ الشائع: حساب 5 × 4 = 20 (عمليّة المساحة) بدل المحيط.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

