INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('184f64db-004c-56a3-b4b1-b4c7f7bc3dd0', 'c8ab06b4-777c-5c49-9ed6-8dac3343864a', 'متى يكون شكلان متناظرين بالنسبة لمستقيم؟', '[{"id":"a","text":"إذا كان لهما اللونُ نفسه"},{"id":"b","text":"إذا انطبق أحدُهما على الآخر عند طيِّ الورقة على ذلك المستقيم"},{"id":"c","text":"إذا كانا متجاورين"},{"id":"d","text":"إذا كان أحدُهما أكبرَ من الآخر"}]'::jsonb, 'b', 'شكلان متناظران بالنسبة لمستقيم (المحور) إذا انطبق أحدُهما على الآخر تمامًا عند طيِّ الورقة على هذا المستقيم.', 1)
