  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('29f88470-e53b-565d-b3c4-e066e422ae24', 'c8ab06b4-777c-5c49-9ed6-8dac3343864a', 'المستقيمُ الذي نطوي عليه الورقةَ فينطبق الشكلان يُسمّى:', '[{"id":"a","text":"محورَ التناظر"},{"id":"b","text":"الضلعَ"},{"id":"c","text":"الرأسَ"},{"id":"d","text":"القطرَ"}]'::jsonb, 'a', 'المستقيمُ الذي يقسم اللوحةَ إلى نصفين نظيرين، ونطوي عليه فينطبق الشكلان، يُسمّى محورَ التناظر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a2c3b8c1-1af2-50f9-8ecd-fa8182ecc573', 'c8ab06b4-777c-5c49-9ed6-8dac3343864a', 'هل يحفظ التناظرُ المحوري أطوالَ الأضلاع وقياساتِ الزوايا؟', '[{"id":"a","text":"يغيّر الأطوال فقط"},{"id":"b","text":"يغيّر الزوايا فقط"},{"id":"c","text":"نعم، يحفظ الأطوالَ والزوايا معًا"},{"id":"d","text":"يكبّر الشكلَ"}]'::jsonb, 'c', 'التناظرُ المحوري يقلب الشكلَ كالمرآة دون أن يغيّره: الشكلُ ونظيرُه لهما الأطوالُ نفسها وقياساتُ الزوايا نفسها.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9e4e05f6-c06b-5e5e-af5c-e722a8a0cd76', 'c8ab06b4-777c-5c49-9ed6-8dac3343864a', 'كم محورَ تناظرٍ للمربّع؟ <svg viewBox="0 0 90 90"><rect x="18" y="18" width="54" height="54" fill="none" stroke="currentColor" stroke-width="2.5"/><line x1="45" y1="12" x2="45" y2="78" stroke="#ef4444" stroke-width="1.5" stroke-dasharray="4,3"/><line x1="12" y1="45" x2="78" y2="45" stroke="#ef4444" stroke-width="1.5" stroke-dasharray="4,3"/><line x1="14" y1="14" x2="76" y2="76" stroke="#ef4444" stroke-width="1.5" stroke-dasharray="4,3"/><line x1="76" y1="14" x2="14" y2="76" stroke="#ef4444" stroke-width="1.5" stroke-dasharray="4,3"/></svg>', '[{"id":"a","text":"2"},{"id":"b","text":"1"},{"id":"c","text":"3"},{"id":"d","text":"4"}]'::jsonb, 'd', 'للمربّع 4 محاور تناظر: محوران يمرّان بمنتصفات الأضلاع ومحوران قُطْريّان، كما تبيّن الخطوطُ المنقّطة الأربعة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6976855d-dbad-5d17-88b9-7a0624a50091', 'c8ab06b4-777c-5c49-9ed6-8dac3343864a', 'نقطةٌ A وصورتُها B بالنسبة لمحور. أين تقعُ B؟', '[{"id":"a","text":"على المحور نفسه"},{"id":"b","text":"على بُعدٍ من المحور يساوي بُعدَ A عنه، على الجانب الآخر"},{"id":"c","text":"أقربَ إلى المحور من A"},{"id":"d","text":"أبعدَ عن المحور من A"}]'::jsonb, 'b', 'كلُّ نقطةٍ وصورتُها على بُعدٍ متساوٍ من المحور وعلى عمودٍ عليه، فتقعُ B على الجانب الآخر على البعد نفسه الذي تبعده A.', 5)
ON CONFLICT (id) DO UPDATE SET
