INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dcf1bb77-751d-59fc-a546-0e5b7e852741', '18769fea-963e-5dd7-bd4e-852e90ce0752', 'بأيِّ خطٍّ نرسم محورَ التناظر عادةً لتمييزه؟', '[{"id":"a","text":"خطٌّ منقّط"},{"id":"b","text":"خطٌّ سميكٌ أحمر ممتلئ"},{"id":"c","text":"خطٌّ منحنٍ"},{"id":"d","text":"دائرة"}]'::jsonb, 'a', 'نرسم محورَ التناظر بخطٍّ منقّط لتمييزه عن أضلاع الشكل نفسه.', 2)
