INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('11d707d5-c58e-54d5-9a3e-7ffc3ae14db6', '18769fea-963e-5dd7-bd4e-852e90ce0752', 'الشكلُ الناتجُ عن التناظر يُسمّى:', '[{"id":"a","text":"المحورَ"},{"id":"b","text":"الرأسَ"},{"id":"c","text":"نظيرَ الشكل (صورتَه)"},{"id":"d","text":"الضلعَ"}]'::jsonb, 'c', 'الشكلُ الثاني الناتجُ عن التناظر بالنسبة للمحور يُسمّى نظيرَ الشكل الأوّل أو صورتَه.', 3)
