INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a689f23-e0b0-52c1-8bf9-9ee42504feda', '18769fea-963e-5dd7-bd4e-852e90ce0752', 'كم محورَ تناظرٍ للمستطيل؟ <svg viewBox="0 0 110 80"><rect x="20" y="25" width="70" height="38" fill="none" stroke="currentColor" stroke-width="2.5"/><line x1="55" y1="18" x2="55" y2="70" stroke="#ef4444" stroke-width="1.5" stroke-dasharray="4,3"/><line x1="13" y1="44" x2="97" y2="44" stroke="#ef4444" stroke-width="1.5" stroke-dasharray="4,3"/></svg>', '[{"id":"a","text":"4"},{"id":"b","text":"2"},{"id":"c","text":"1"},{"id":"d","text":"3"}]'::jsonb, 'b', 'للمستطيل محوران (2) فقط، يمرّان بمنتصفات الأضلاع المتقابلة، كما يبيّن الخطّان المنقّطان. قُطْراه ليسا محوري تناظر.', 4)
ON CONFLICT (id) DO UPDATE SET
