  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6dbfbb5-d09f-5e6e-a2c8-b04817df0672', '18769fea-963e-5dd7-bd4e-852e90ce0752', 'أيُّ هذه الأشكال له عددٌ لا نهائي من محاور التناظر؟', '[{"id":"a","text":"المربّع"},{"id":"b","text":"المثلّث"},{"id":"c","text":"المستطيل"},{"id":"d","text":"الدائرة"}]'::jsonb, 'd', 'كلُّ مستقيمٍ يمرّ بمركز الدائرة هو محورُ تناظرٍ لها، فعددُ محاورها لا نهائي.', 5)
