INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('150e20ec-6eed-5c27-8043-417110eec92c', '18769fea-963e-5dd7-bd4e-852e90ce0752', 'هل الفراشةُ المرسومةُ بنصفين متطابقين على جانبَي خطٍّ في وسطها شكلٌ متناظر؟ <svg viewBox="0 0 100 80"><line x1="50" y1="10" x2="50" y2="70" stroke="#ef4444" stroke-width="2" stroke-dasharray="5,4"/><path d="M50 40 C 30 18, 12 30, 28 48 C 16 58, 36 64, 50 52" fill="none" stroke="currentColor" stroke-width="2"/><path d="M50 40 C 70 18, 88 30, 72 48 C 84 58, 64 64, 50 52" fill="none" stroke="currentColor" stroke-width="2"/></svg>', '[{"id":"a","text":"نعم، والخطُّ في وسطها محورُ تناظر"},{"id":"b","text":"لا، لأنّ لها لونًا واحدًا"},{"id":"c","text":"لا، لأنّها كبيرة"},{"id":"d","text":"لا يمكن معرفةُ ذلك"}]'::jsonb, 'a', 'نصفا الفراشة متطابقان وينطبقان عند الطيِّ على الخطّ الأوسط، فهي شكلٌ متناظر والخطُّ المنقّطُ محورُ تناظرها.', 6)
