INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eedb52ec-e8a6-56ed-9d99-b334e9672ae8', '1feed6f3-77e7-5d73-bfb4-bbf2e683f635', 'المثلّثُ المتساوي الأضلاع (كلُّ أضلاعه متساوية) كم محورَ تناظرٍ له؟', '[{"id":"a","text":"1"},{"id":"b","text":"3"},{"id":"c","text":"2"},{"id":"d","text":"لا محورَ له"}]'::jsonb, 'b', 'للمثلّث المتساوي الأضلاع 3 محاور تناظر، يمرّ كلٌّ منها برأسٍ ومنتصفِ الضلع المقابل له.', 1)
