INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1ec7edb-b79b-5363-a015-4e5d5de5683e', '1feed6f3-77e7-5d73-bfb4-bbf2e683f635', 'النقطةُ A تبعد 4 وحدات عن المحور. على أيِّ بُعدٍ تقعُ صورتُها B؟', '[{"id":"a","text":"4 وحدات على الجانب الآخر"},{"id":"b","text":"8 وحدات"},{"id":"c","text":"وحدتان"},{"id":"d","text":"على المحور"}]'::jsonb, 'a', 'النقطةُ وصورتُها على بُعدٍ متساوٍ من المحور، فإذا بعدت A أربعَ وحدات بعدت B أربعَ وحدات على الجانب الآخر. الخطأ الشائع جمعُ البعدين (8)؛ البُعدان متساويان لا مجموعان.', 2)
