INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58007d7b-ef02-5d56-8053-2eab4fe0e6bc', '1feed6f3-77e7-5d73-bfb4-bbf2e683f635', 'هل هذا الخطُّ المنقّطُ (قطرُ المستطيل) محورُ تناظرٍ للمستطيل؟ <svg viewBox="0 0 110 80"><rect x="20" y="24" width="70" height="38" fill="none" stroke="currentColor" stroke-width="2.5"/><line x1="20" y1="62" x2="90" y2="24" stroke="#ef4444" stroke-width="1.8" stroke-dasharray="5,4"/></svg>', '[{"id":"a","text":"نعم، كلُّ قطرٍ محورُ تناظر"},{"id":"b","text":"لا، قطرُ المستطيل ليس محورَ تناظر"},{"id":"c","text":"نعم، لأنّه يقسمه إلى نصفين"},{"id":"d","text":"نعم، لأنّه أحمر"}]'::jsonb, 'b', 'قطرُ المستطيل ليس محورَ تناظر: لو طويتَ المستطيلَ على قطره لا ينطبق النصفان. الخطأ الشائع اعتقادُ أنّ كلَّ خطٍّ يقسم الشكلَ نصفين هو محورُ تناظر؛ المستطيلُ له محوران فقط يمرّان بمنتصفات الأضلاع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1d3c4d3-543b-584e-9312-d85c460450c3', '1feed6f3-77e7-5d73-bfb4-bbf2e683f635', 'للمربّع 4 محاورِ تناظر وللمستطيل 2. كم محورًا للمربّع أكثرُ من المستطيل؟', '[{"id":"a","text":"1"},{"id":"b","text":"4"},{"id":"c","text":"2"},{"id":"d","text":"متساويان"}]'::jsonb, 'c', 'للمربّع 4 محاور وللمستطيل 2، والفرق 4 − 2 = 2 محورين أكثر. للمربّع محورا الأضلاع والمحوران القُطْريّان معًا.', 4)
