INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84b45d4e-164f-589b-8c0a-d0a637bade51', '1feed6f3-77e7-5d73-bfb4-bbf2e683f635', 'أيُّ هذه الجُمل صحيحةٌ عن خصائص التناظر المحوري؟', '[{"id":"a","text":"يكبّر أطوالَ الأضلاع"},{"id":"b","text":"يغيّر قياساتِ الزوايا"},{"id":"c","text":"يحفظ الأطوالَ والزوايا، فالشكلُ ونظيرُه متطابقان"},{"id":"d","text":"يحوّل المثلّثَ إلى مربّع"}]'::jsonb, 'c', 'التناظرُ المحوري يحفظ الأطوالَ وقياساتِ الزوايا، فالشكلُ ونظيرُه متطابقان تمامًا في الحجم والقياس، ويختلفان فقط في الاتّجاه كالمرآة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7066af79-5839-5442-bcb7-b749b785b20d', '1feed6f3-77e7-5d73-bfb4-bbf2e683f635', 'المثلّثُ المتساوي الساقين (له ضلعان متساويان فقط) كم محورَ تناظرٍ له؟', '[{"id":"a","text":"3"},{"id":"b","text":"2"},{"id":"c","text":"لا محورَ له"},{"id":"d","text":"1"}]'::jsonb, 'd', 'للمثلّث المتساوي الساقين محورُ تناظرٍ واحدٌ (1) فقط، يمرّ بالرأس بين الضلعين المتساويين وبمنتصفِ القاعدة. الخطأ الشائع إعطاؤه 3 محاور كالمتساوي الأضلاع؛ هنا ضلعان فقط متساويان فالمحور واحد.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

