  ('75ea32c5-c895-5bf8-841a-ab389eae3a60', 'ecc3f34d-26eb-5588-a017-d283e7881519', 'math-4eme', '⭐⭐ تمرين مراجعة (نمط امتحان): التناظر المحوري', 2, 75, 15, 'practice', 'admin', 3)
