INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03762d97-2922-5e1d-8c14-4d9dcb8a3408', '75ea32c5-c895-5bf8-841a-ab389eae3a60', 'أيُّ هذه الأشكال له محورُ تناظرٍ واحدٌ فقط؟', '[{"id":"a","text":"المربّع"},{"id":"b","text":"المثلّث المتساوي الساقين"},{"id":"c","text":"الدائرة"},{"id":"d","text":"المستطيل"}]'::jsonb, 'b', 'المثلّثُ المتساوي الساقين له محورُ تناظرٍ واحدٌ يمرّ بالرأس ومنتصفِ القاعدة. المربّع له 4، المستطيل 2، والدائرة عددٌ لا نهائي.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a45e0ec-5048-5165-ad12-57ecf5ec3a12', '75ea32c5-c895-5bf8-841a-ab389eae3a60', 'نريد رسمَ نظيرِ شكلٍ بالنسبة لمحور. ماذا نفعل لكلِّ رأس؟', '[{"id":"a","text":"نضعه على المحور"},{"id":"b","text":"نضاعفُ بُعده عن المحور"},{"id":"c","text":"نقرّبه من المحور قليلًا"},{"id":"d","text":"ننقله إلى الجانب الآخر على البعد نفسه من المحور"}]'::jsonb, 'd', 'لرسم النظير ننقل كلَّ رأسٍ إلى الجانب الآخر من المحور على البعد نفسه، ثمّ نصلُ النقاط بالترتيب نفسه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c22a1a73-477f-5572-af77-e8a5c8e948a5', '75ea32c5-c895-5bf8-841a-ab389eae3a60', 'أيُّ نقطةٍ من النقطتين الحمراوين هي الصورةُ الصحيحةُ للنقطة A بالنسبة للمحور؟ <svg viewBox="0 0 130 70"><line x1="65" y1="8" x2="65" y2="62" stroke="#ef4444" stroke-width="2" stroke-dasharray="5,4"/><circle cx="45" cy="35" r="3" fill="currentColor"/><text x="38" y="30" font-size="11" fill="currentColor">A</text><circle cx="85" cy="35" r="3" fill="currentColor"/><text x="82" y="30" font-size="11" fill="currentColor">P</text><circle cx="110" cy="35" r="3" fill="currentColor"/><text x="107" y="30" font-size="11" fill="currentColor">Q</text></svg>', '[{"id":"a","text":"النقطة P (على بُعدٍ مساوٍ لبُعد A)"},{"id":"b","text":"النقطة Q"},{"id":"c","text":"كلتاهما صحيحتان"},{"id":"d","text":"لا توجد صورة صحيحة"}]'::jsonb, 'a', 'A تبعد 20 وحدةً عن المحور، والصورةُ يجب أن تبعد المقدارَ نفسه على الجانب الآخر؛ وهذه هي P. أمّا Q فأبعدُ من اللازم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ab7d1f7-3c44-53c2-9879-ad55fdfc143a', '75ea32c5-c895-5bf8-841a-ab389eae3a60', 'شكلٌ ونظيرُه بالنسبة لمحور. إذا كان طولُ ضلعٍ في الشكل الأصلي 6 سم، فما طولُ الضلع المقابل له في النظير؟', '[{"id":"a","text":"3 سم"},{"id":"b","text":"12 سم"},{"id":"c","text":"6 سم"},{"id":"d","text":"لا يمكن معرفتُه"}]'::jsonb, 'c', 'التناظرُ يحفظ الأطوال، فالضلعُ وصورتُه لهما الطولُ نفسه: 6 سم. الشكلُ ونظيرُه متطابقان في القياسات.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f3303651-c9e2-559c-81f2-0df8d97e25af', '75ea32c5-c895-5bf8-841a-ab389eae3a60', 'نكمل نصفَ الشكل المرسوم بالخطّ المتّصل ليصير متناظرًا بالنسبة للمحور المنقّط. أيُّ نصفٍ (منقّطٍ) هو الإكمالُ الصحيح؟ <svg viewBox="0 0 130 80"><line x1="65" y1="8" x2="65" y2="72" stroke="#ef4444" stroke-width="2" stroke-dasharray="5,4"/><polyline points="65,18 40,18 40,62 65,62" fill="none" stroke="currentColor" stroke-width="2.5"/><polyline points="65,18 90,18 90,62 65,62" fill="none" stroke="currentColor" stroke-width="2" stroke-dasharray="3,3"/></svg>', '[{"id":"a","text":"النصفُ المنقّطُ على اليمين (نسخةُ النصف الأيسر على البعد نفسه)"},{"id":"b","text":"نصفٌ أصغرُ من الأصلي"},{"id":"c","text":"نصفٌ أبعدُ عن المحور"},{"id":"d","text":"لا نحتاج إكمالًا"}]'::jsonb, 'a', 'الإكمالُ الصحيح هو نسخةُ النصف الأيسر منقولةً إلى الجانب الأيمن على البعد نفسه من المحور، تمامًا كالخطّ المنقّط في الرسم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('793fab9e-86e5-5c94-b21e-cbc1c7262f0b', '75ea32c5-c895-5bf8-841a-ab389eae3a60', 'أيُّ الجُمل التالية خاطئةٌ عن محاور التناظر؟', '[{"id":"a","text":"للمربّع 4 محاور"},{"id":"b","text":"للمستطيل 2 محورين"},{"id":"c","text":"للمستطيل 4 محاور مثل المربّع"},{"id":"d","text":"للدائرة عددٌ لا نهائي من المحاور"}]'::jsonb, 'c', 'الجملةُ الخاطئةُ هي أنّ للمستطيل 4 محاور؛ المستطيلُ له محوران فقط، أمّا المربّع فله 4. باقي الجُمل صحيحة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

