INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('49ae65b0-0a63-505f-bb9c-85a8dc502438', 'b6ac340d-7de8-5dc5-90ca-8954a8d2f71b', 'أنا شكلٌ لي عددٌ لا نهائي من محاور التناظر، يمرّ كلٌّ منها بمركزي. من أكون؟', '[{"id":"a","text":"الدائرة"},{"id":"b","text":"المربّع"},{"id":"c","text":"المثلّث المتساوي الأضلاع"},{"id":"d","text":"المستطيل"}]'::jsonb, 'a', 'كلُّ مستقيمٍ يمرّ بمركز الدائرة يقسمها إلى نصفين منطبقين، فعددُ محاورها لا نهائي؛ وهذا لا يصحُّ لأيِّ شكلٍ آخر.', 1)
ON CONFLICT (id) DO UPDATE SET
