  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('957fb9ed-9055-543b-a41f-cd30e5f9f60f', 'b6ac340d-7de8-5dc5-90ca-8954a8d2f71b', 'النقطةُ A وصورتُها B بالنسبة لمحور. ماذا يمثّل المحورُ بالنسبة للقطعة [AB]؟', '[{"id":"a","text":"امتدادًا لها"},{"id":"b","text":"مستقيمًا عموديًّا عليها يقطعها في منتصفها"},{"id":"c","text":"مستقيمًا موازيًا لها"},{"id":"d","text":"نقطةً عليها"}]'::jsonb, 'b', 'النقطةُ وصورتُها على بُعدٍ متساوٍ من المحور وعلى عمودٍ عليه، فالمحورُ عموديٌّ على [AB] ويقطعها في منتصفها بالضبط.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('15bb7877-b728-526f-89e8-911cf1ed46cd', 'b6ac340d-7de8-5dc5-90ca-8954a8d2f71b', 'مثلّثان متناظران بالنسبة لمحور. زاويةٌ في الأوّل قياسُها 50°. ما قياسُ الزاوية المقابلة لها في النظير؟', '[{"id":"a","text":"100°"},{"id":"b","text":"25°"},{"id":"c","text":"40°"},{"id":"d","text":"50°"}]'::jsonb, 'd', 'التناظرُ يحفظ قياساتِ الزوايا، فالزاويةُ وصورتُها لهما القياسُ نفسه: 50°. الخطأ الشائع مضاعفةُ القياس (100°)؛ التناظرُ لا يكبّر شيئًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('52c03c04-5f6c-58cc-b618-881dbb79e92d', 'b6ac340d-7de8-5dc5-90ca-8954a8d2f71b', 'للمربّع 4 محاور، وللمثلّث المتساوي الأضلاع 3، وللمستطيل 2. ما مجموعُ محاور تناظر هذه الأشكال الثلاثة؟', '[{"id":"a","text":"8"},{"id":"b","text":"9"},{"id":"c","text":"7"},{"id":"d","text":"6"}]'::jsonb, 'b', 'المجموع = 4 + 3 + 2 = 9 محاور. (المربّع 4، المتساوي الأضلاع 3، المستطيل 2.)', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90869bd3-c936-534a-a70d-b26f99e184a4', 'b6ac340d-7de8-5dc5-90ca-8954a8d2f71b', 'هل الخطُّ المنقّطُ محورُ تناظرٍ لهذا الشكل (نصفان غيرُ متطابقين على جانبيه)؟ <svg viewBox="0 0 120 80"><line x1="60" y1="8" x2="60" y2="72" stroke="#ef4444" stroke-width="2" stroke-dasharray="5,4"/><polygon points="30,65 60,65 60,25" fill="none" stroke="currentColor" stroke-width="2.5"/><polygon points="60,65 100,65 60,40" fill="none" stroke="currentColor" stroke-width="2.5"/></svg>', '[{"id":"a","text":"نعم، لأنّه في الوسط"},{"id":"b","text":"نعم، لأنّه منقّط"},{"id":"c","text":"لا، لأنّ النصفين لا ينطبقان عند الطيّ"},{"id":"d","text":"نعم، لأنّه يقسمه إلى جزأين"}]'::jsonb, 'c', 'المثلّثان على جانبَي الخطّ مختلفان في الشكل، فلا ينطبقان عند الطيّ، إذن الخطُّ ليس محورَ تناظر. الخطأ الشائع الاكتفاءُ بأنّ الخطّ في الوسط؛ شرطُ المحور هو انطباقُ النصفين، لا موضعُ الخطّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91532cde-ca7d-56c4-8308-ffd964dafa41', 'b6ac340d-7de8-5dc5-90ca-8954a8d2f71b', 'أنا مثلّثٌ لي محورُ تناظرٍ واحدٌ فقط يمرّ برأسي ومنتصفِ قاعدتي. من أكون؟', '[{"id":"a","text":"مثلّثٌ متساوي الأضلاع"},{"id":"b","text":"مثلّثٌ مختلفُ الأضلاع (بلا محور)"},{"id":"c","text":"مثلّثٌ متساوي الساقين"},{"id":"d","text":"مربّع"}]'::jsonb, 'c', 'المثلّثُ ذو المحور الواحد المارِّ بالرأس ومنتصفِ القاعدة هو المتساوي الساقين. المتساوي الأضلاع له 3 محاور، والمختلفُ الأضلاع لا محورَ له.', 6)
ON CONFLICT (id) DO UPDATE SET
