INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2ac954c-f4e2-55ae-a956-d8539d33ee88', 'fa134026-98df-5cb3-b23f-80a08c1113aa', 'المستقيمُ الذي إذا طوينا الورقةَ عليه انطبق الشكلان يُسمّى:', '[{"id":"a","text":"القطرَ"},{"id":"b","text":"محورَ التناظر"},{"id":"c","text":"الضلعَ"},{"id":"d","text":"المنصّفَ فقط"}]'::jsonb, 'b', 'المستقيمُ الذي ينطبق عند الطيِّ عليه الشكلان أحدُهما على الآخر هو محورُ التناظر.', 1)
