INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b731e77-c0c5-584d-af60-c4ba170a0af7', 'fa134026-98df-5cb3-b23f-80a08c1113aa', 'وصّل ذهنيًّا: المربّع 4 محاور، والمستطيل 2. أيُّ العبارتين صحيحةٌ معًا؟', '[{"id":"a","text":"للمربّع محاورُ أكثرُ من المستطيل بمحورين"},{"id":"b","text":"للمستطيل محاورُ أكثرُ من المربّع"},{"id":"c","text":"لهما العددُ نفسه من المحاور"},{"id":"d","text":"لا محورَ لأيٍّ منهما"}]'::jsonb, 'a', 'للمربّع 4 وللمستطيل 2، والفرق 4 − 2 = 2، فللمربّع محورين أكثرَ من المستطيل. سببُ الفرق أنّ قُطْرَي المربّع محورا تناظرٍ بينما قطرا المستطيل لا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('799a1503-c76e-59f5-a554-7bc9bc9f871c', 'fa134026-98df-5cb3-b23f-80a08c1113aa', 'النقطةُ M تبعد 5 وحدات عن المحور، وصورتُها M′. ما المسافةُ الكليّة بين M وM′؟', '[{"id":"a","text":"صفر"},{"id":"b","text":"وحدتان ونصف"},{"id":"c","text":"5 وحدات"},{"id":"d","text":"10 وحدات"}]'::jsonb, 'd', 'M تبعد 5 وحدات وM′ تبعد 5 وحدات على الجانب الآخر، والمحورُ بينهما، فالمسافةُ الكليّة = 5 + 5 = 10 وحدات. الخطأ الشائع إعطاءُ 5 (بُعدُ نقطةٍ واحدةٍ فقط) لا المسافةَ الكاملة بينهما.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7326dd36-6e6b-5c74-9200-1600639b2a36', 'fa134026-98df-5cb3-b23f-80a08c1113aa', 'أيُّ هذه الأشكال له أكبرُ عددٍ مُحدَّدٍ (منتهٍ) من محاور التناظر؟', '[{"id":"a","text":"المثلّث المتساوي الساقين"},{"id":"b","text":"المستطيل"},{"id":"c","text":"المثلّث المتساوي الأضلاع"},{"id":"d","text":"المربّع"}]'::jsonb, 'd', 'المربّع له 4 محاور، وهو الأكبرُ بين هذه الأشكال ذات العدد المنتهي: المتساوي الأضلاع 3، المستطيل 2، المتساوي الساقين 1. (الدائرةُ وحدها لا نهائية ولم تُذكَر هنا.)', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19b33d8d-ac8c-5a27-8c6d-74f1f2463646', 'fa134026-98df-5cb3-b23f-80a08c1113aa', 'مثلّثان متناظران بالنسبة لمحور، طولُ ضلعٍ في الأوّل 7 سم وقياسُ زاويةٍ فيه 60°. ما طولُ الضلع المقابل وقياسُ الزاوية المقابلة في النظير؟', '[{"id":"a","text":"14 سم و120°"},{"id":"b","text":"7 سم و60°"},{"id":"c","text":"3,5 سم و30°"},{"id":"d","text":"7 سم و120°"}]'::jsonb, 'b', 'التناظرُ يحفظ الأطوالَ والزوايا معًا، فالضلعُ المقابلُ 7 سم والزاويةُ المقابلةُ 60° دون تغيير. الخطأ الشائع مضاعفةُ القيم؛ التناظرُ يقلب الاتّجاه فقط ولا يغيّر القياسات.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

